import React from 'react'
import { DialogOverlay, Paragraph, DialogOverlayFooter, DialogOverlayActions, Button } from '@fs/zion-ui'
import { useTranslation } from 'react-i18next'
import type { UseOverlayReturnOptions } from '@fs/zion-ui'

type Props = {
  overlay: UseOverlayReturnOptions
}

export default function LivingPersonDeathLikeMessage({ overlay }: Props): JSX.Element {
  const [t] = useTranslation()
  return (
    <DialogOverlay title={t('conclusion.livingPerson.header')} {...overlay}>
      <Paragraph size="sm">{t('conclusion.livingPerson.warningText')}</Paragraph>
      <DialogOverlayFooter>
        <DialogOverlayActions>
          <Button onClick={overlay.close} emphasis="high">
            {t('common-ui:ok.action')}
          </Button>
        </DialogOverlayActions>
      </DialogOverlayFooter>
    </DialogOverlay>
  )
}
