import { useEffect, useRef, useState } from 'react'
import type { UseZionFormReturn, FieldValues } from '@fs/zion-form'
import { debug } from '../helpers'
import useSyncFieldsToStorage from './useSyncFieldsToStorage'

type RemoveStoredFieldsFunction = () => Promise<void>

type Props<TFieldValues extends FieldValues = FieldValues> = Parameters<
  typeof useSyncFieldsToStorage<TFieldValues>
>[0] & {
  methods: Pick<UseZionFormReturn<TFieldValues>, 'reset'>
  /** The value for if the Dialog is open or not (should be provided by useOverlay) */
  isOpen: boolean
}

// This version of the hook handles clearing storage when the dialog is closed by the user intentionally (cancel button, click-away, close button, submit, whatever)
export default function useSyncDialogFieldsToStorage<TFieldValues extends FieldValues = FieldValues>({
  isOpen,
  methods,
  fieldNamesAndDefaults,
  baseDatabaseKey,
  storeName,
}: Props<TFieldValues>): RemoveStoredFieldsFunction {
  const { reset } = methods
  const [canUpdateStorage, setCanUpdateStorage] = useState(true)
  const removeFieldsFromStorage = useSyncFieldsToStorage<TFieldValues>({
    storeName,
    baseDatabaseKey,
    methods,
    fieldNamesAndDefaults,
    canUpdateStorage,
  })
  const wasOpen = useRef(isOpen)
  useEffect(() => {
    if (!isOpen && wasOpen.current) {
      debug(
        `Resetting fields and removing the stored values.\nstoreName=${storeName}\nbaseDatabaseKey=${baseDatabaseKey}`
      )
      wasOpen.current = false
      setCanUpdateStorage(false)
      reset()
      removeFieldsFromStorage()
    }
    if (isOpen) {
      setCanUpdateStorage(true)
      wasOpen.current = true
    }
  }, [isOpen, reset, removeFieldsFromStorage, setCanUpdateStorage, storeName, baseDatabaseKey])

  return removeFieldsFromStorage
}
