import React, { type ReactNode } from 'react'
import { Bleed, Grid, useContainerWidth, colors, LayoutBand } from '@fs/zion-ui'
import { css, cx } from '@linaria/core'

const growFlexContainerCss = css`
  display: flex;
  flex-grow: 1;
`

const centeredCss = css`
  width: 100%;
  max-width: 80ch;
  margin: 0 auto;
`

type SplitDialogContentProps = {
  left: ReactNode
  right?: ReactNode
  fullColumns?: boolean
  growFlexLeft?: boolean
}

/**
 * Splits the content of a dialog into two columns. The right side has a shaded background.
 */
export default function SplitDialogContent({
  left,
  right,
  fullColumns = false,
  growFlexLeft,
}: SplitDialogContentProps): JSX.Element {
  const atWidth = useContainerWidth()
  const columns = fullColumns ? 12 : atWidth({ default: 12, md: right ? 6 : 12 })

  return (
    <Bleed top={columns !== 12} bottom>
      <LayoutBand growY>
        <Grid guttersX="lg" guttersY="md" growY>
          <LayoutBand columns={columns}>
            <div
              className={cx(growFlexLeft ? growFlexContainerCss : undefined, columns === 12 ? centeredCss : undefined)}
            >
              {left}
            </div>
          </LayoutBand>
          {!!right && (
            <LayoutBand growY columns={columns} color={colors.gray02}>
              <div className={columns === 12 ? centeredCss : undefined}>{right}</div>
            </LayoutBand>
          )}
        </Grid>
      </LayoutBand>
    </Bleed>
  )
}
