import React, { useRef, useEffect, Fragment, useState } from 'react'
import { DialogOverlay, DialogOverlayActions, Button, Row, List, ListItem, Alert, H3 } from '@fs/zion-ui'
import { useTranslation } from 'react-i18next'
import { IssueImprovement, IssueLabel, type IssueType } from '@fs/zion-person-quality-score-issues'
import { trackEvent } from '@fs/zion-analytics'
import type { UseOverlayReturnOptions } from '@fs/zion-ui'
import type { QualityScoreIssue, PersonScoresDelta } from '../../types/qualityScore'
import { calculateScoreChange } from './helperFunctions'

// Component to display issues grouped by score type with "view more" functionality
function IssuesList({ issues }: { issues: QualityScoreIssue[] }): JSX.Element {
  const [t] = useTranslation()
  const [expandedSections, setExpandedSections] = useState<Record<string, boolean>>({})

  // Group issues by scoreType and sort by penalty (descending - higher penalty = more important)
  const groupedIssues = issues.reduce(
    (acc, issue) => {
      if (!acc[issue.scoreType]) {
        acc[issue.scoreType] = []
      }
      acc[issue.scoreType].push(issue)
      return acc
    },
    {} as Record<IssueType, QualityScoreIssue[]>
  )

  // Sort issues within each group by penalty (descending)
  Object.keys(groupedIssues).forEach((scoreType) => {
    groupedIssues[scoreType as IssueType].sort((a, b) => (b.penalty || 0) - (a.penalty || 0))
  })
  // put coherence first if it has any issues
  const orderedScoreTypes =
    groupedIssues.COHERENCE?.length > 0
      ? (['COHERENCE', ...Object.keys(groupedIssues).filter((type) => type !== 'COHERENCE')] as IssueType[])
      : (Object.keys(groupedIssues) as IssueType[])

  const toggleSection = (scoreType: string): void => {
    setExpandedSections((prev) => ({
      ...prev,
      [scoreType]: !prev[scoreType],
    }))
  }

  const MAX_VISIBLE_ISSUES = 3

  return (
    <List>
      {orderedScoreTypes.map((scoreType) => {
        const issueList = groupedIssues[scoreType]
        const isExpanded = expandedSections[scoreType] || false
        const visibleIssues = isExpanded ? issueList : issueList.slice(0, MAX_VISIBLE_ISSUES)
        const hasMoreIssues = issueList.length > MAX_VISIBLE_ISSUES

        return (
          <Fragment key={scoreType}>
            <ListItem
              primaryText={
                <H3 size="H6">
                  <IssueLabel issueType={scoreType} issueCount={issueList.length} />
                </H3>
              }
            />
            {visibleIssues.map((issue) => (
              <IssueImprovement key={issue.id} issue={issue} />
            ))}
            {hasMoreIssues && (
              <ListItem
                primaryText={
                  <Button emphasis="low" onClick={() => toggleSection(scoreType)}>
                    {isExpanded
                      ? t('conclusion.quality-score-warning.view-less')
                      : t('conclusion.quality-score-warning.view-more', {
                          count: issueList.length - MAX_VISIBLE_ISSUES,
                        })}
                  </Button>
                }
              />
            )}
          </Fragment>
        )
      })}
    </List>
  )
}

type QualityScoreWarningDialogProps = {
  overlay: UseOverlayReturnOptions
  onSave: () => void
  onCancel: () => void
  personScoresDelta?: PersonScoresDelta
  /** Add conclusion type for analytics */
  conclusionType?: string
  actionType?: 'Add' | 'Edit' | 'Delete'
}

export default function QualityScoreWarningDialog({
  overlay,
  onSave,
  onCancel,
  personScoresDelta,
  conclusionType,
  actionType,
}: QualityScoreWarningDialogProps): JSX.Element {
  const [t] = useTranslation()
  const saveRef = useRef<HTMLButtonElement>(null)

  // Track if Person Quality Score will be higher or lower with this edit.
  const scoreChange = calculateScoreChange(
    personScoresDelta?.currentScores.overallRawScore,
    personScoresDelta?.newScores.overallRawScore
  )

  // Track conclusion dialog shown when THIS overlay is open
  useEffect(() => {
    if (!overlay.isOpen) return
    trackEvent({
      event_name: 'conclusion_quality_score_warning_dialog_shown',
      issues_count: personScoresDelta?.issuesAdded.length,
      quality_score_saved: scoreChange,
      conclusion_type: conclusionType,
      action_type: actionType,
    })
  }, [overlay.isOpen, personScoresDelta?.issuesAdded.length, scoreChange, conclusionType, actionType])

  const handleSave = (): void => {
    trackEvent({
      event_name: 'conclusion_quality_score_warning_dialog_save_clicked',
      issues_count: personScoresDelta?.issuesAdded.length,
      quality_score_saved: scoreChange,
      conclusion_type: conclusionType,
      action_type: actionType,
    })

    onSave()
    overlay.close()
  }

  const handleCancel = (): void => {
    onCancel()
    overlay.close()
  }

  return (
    <DialogOverlay
      {...overlay}
      focusRef={saveRef}
      title={t('conclusion.quality-score-warning.header', {
        count: personScoresDelta?.issuesAdded.length,
      })}
      footer={
        <DialogOverlayActions>
          <Row>
            <Button data-testid="qualityScoreWarningCancelButton" onClick={handleCancel}>
              {t('common-ui:cancel.action')}
            </Button>

            <Button
              ref={saveRef}
              data-testid="qualityScoreWarningSaveButton"
              type="submit"
              emphasis="high"
              onClick={handleSave}
            >
              {t('common-ui:save.action')}
            </Button>
          </Row>
        </DialogOverlayActions>
      }
    >
      <Alert type="warning">{t('conclusion.quality-score-warning.body')}</Alert>
      {personScoresDelta?.issuesAdded && personScoresDelta.issuesAdded.length > 0 && (
        <IssuesList issues={personScoresDelta.issuesAdded} />
      )}
    </DialogOverlay>
  )
}
