import React, { type ComponentProps, useEffect, useState, useRef } from 'react'
import { useStatusOverlay, DialogOverlayActions, Button, DangerButton, useOverlayUpdate, useOverlay } from '@fs/zion-ui'
import { useTranslation } from 'react-i18next'
import { NoticeLoading } from '@fs/zion-icon'
import { useHistory } from '@fs/zion-router'
import type { Conclusion, CoupleId, PersonId } from '@fs/zion-tree-types'
import { useFeatureFlag } from '@fs/zion-flags'
import { trackEvent } from '@fs/zion-analytics'
import { type UseFormResetField } from '@fs/zion-form'
import ReasonForm from '../ReasonForm'
import { convertFormDataToTreeData, getDeleteSuggestedReasonsType } from '../../helpers/helpers'
import deleteConclusion from '../../data-service/deleteConclusion'
import validateConclusionQuality from '../../data-service/validateConclusionQuality'
import QualityScoreWarningDialog from './QualityScoreWarningDialog'
import { calculateScoreChange } from './helperFunctions'
import QualityScoreWarningDialogV2 from './QualityScoreWarningDialogV2'

type DeleteConclusionViewFooterProps = {
  deleting: boolean
  deleteLabel: string
}

export function DeleteConclusionViewFooter({ deleting, deleteLabel }: DeleteConclusionViewFooterProps): JSX.Element {
  const [t] = useTranslation()
  const history = useHistory()
  return (
    <DialogOverlayActions>
      <Button
        data-testid="ConclusionDialog:delete:button"
        onClick={() => history.goBack()}
        emphasis="low"
        disabled={deleting}
      >
        {t('common-ui:cancel.action')}
      </Button>
      <DangerButton
        data-testid="delete-submit-button"
        type="submit"
        form="reason-form"
        disabled={deleting}
        Icon={deleting ? NoticeLoading : undefined}
      >
        {deleteLabel}
      </DangerButton>
    </DialogOverlayActions>
  )
}

type DeleteConclusionViewProps = {
  conclusion: Conclusion
  personId: PersonId
  relationshipId?: string
  deleteLabel: string
  deleting: boolean
  // TODO make this required
  /** Optional for now, but required for new quality score validation */
  personName?: string
  setDeleting: (deleting: boolean) => void
  onDelete?: () => void

  /** CoupleId for adding to PubSub -- needed for adding relationship type for a parent-child relationship */
  coupleId?: CoupleId
}

export default function DeleteConclusionView({
  conclusion,
  personId,
  relationshipId,
  deleteLabel,
  personName,
  deleting,
  setDeleting,
  onDelete,
  coupleId,
}: DeleteConclusionViewProps): JSX.Element {
  const showStatusOverlay = useStatusOverlay()
  const { t } = useTranslation()
  const history = useHistory()
  const qualityScoreWarningFlagIsOn = useFeatureFlag('treeWeb_conclusion_pqsWarning').isOn
  const isQualityScoreWarningDialogV2On = useFeatureFlag('treeWeb_conclusion_pqsWarningDialogV2').isOn
  // State for quality score validation
  const [qualityScoreWarningProps, setQualityScoreWarningProps] = useState<Pick<
    ComponentProps<typeof QualityScoreWarningDialogV2>,
    'personScoresDelta' | 'defaultValues'
  > | null>(null)
  const qualityScoreWarningOverlay = useOverlay()
  const resetFieldRef = useRef<UseFormResetField<{ reason: string }>>()

  // Helper function to check if conclusion type is vital
  const isVitalConclusionType = (conclusionType: string): boolean => {
    const vitalTypes = ['BIRTH', 'DEATH', 'CHRISTENING', 'BURIAL', 'GENDER', 'NAME']
    return vitalTypes.includes(conclusionType)
  }

  const performDelete = async (newConclusion: Conclusion, scoreChange?: string): Promise<void> => {
    try {
      await deleteConclusion(newConclusion, relationshipId || personId, coupleId || history.location.state?.coupleId)
      onDelete?.()
      // Fires after a completed deletion
      trackEvent({
        link_name: `Delete ${conclusion.type} conclusion`,
        quality_score_saved: scoreChange,
      })
      setDeleting(false)
    } catch (error) {
      showStatusOverlay({ type: 'error', message: t('conclusion.delete.error') })
      setDeleting(false)
    }
  }

  const onQualityScoreWarningSave = async (): Promise<void> => {
    qualityScoreWarningOverlay.close()
    setDeleting(true)
    const newConclusion = convertFormDataToTreeData(
      { justification: qualityScoreWarningProps?.defaultValues.reason },
      conclusion
    )
    await performDelete(newConclusion)
  }

  const onQualityScoreWarningSaveV2: ComponentProps<typeof QualityScoreWarningDialogV2>['onSave'] = async (
    pqsValue
  ): Promise<void> => {
    resetFieldRef.current?.('reason', { defaultValue: pqsValue.reason })
    qualityScoreWarningOverlay.close()
    setDeleting(true)
    const newConclusion = convertFormDataToTreeData({ justification: pqsValue.reason }, conclusion)
    await performDelete(newConclusion)
  }

  const onQualityScoreWarningCancel = (): void => {
    qualityScoreWarningOverlay.close()
  }

  const onSubmit: ComponentProps<typeof ReasonForm>['onSubmit'] = async (
    { reason: justification },
    resetField
  ): Promise<void> => {
    resetFieldRef.current = resetField
    setDeleting(true)
    const newConclusion = convertFormDataToTreeData({ justification }, conclusion)

    // Check if quality score validation should be performed
    const shouldValidateQualityScore = qualityScoreWarningFlagIsOn && isVitalConclusionType(conclusion.type)

    if (!shouldValidateQualityScore) {
      // Skip quality validation and proceed with delete
      await performDelete(newConclusion)
      return
    }

    try {
      const { shouldWarn, response } = await validateConclusionQuality({
        personId,
        conclusionToDelete: conclusion.id,
      })

      // We want to track if we are going from a higher Person Quality Score to a lower one with this edit. Or if the score is rather improving
      const scoreChange = calculateScoreChange(
        response?.personScoresDelta?.currentScores.overallRawScore,
        response?.personScoresDelta?.newScores.overallRawScore
      )

      if (shouldWarn && response) {
        setDeleting(false)
        setQualityScoreWarningProps({
          personScoresDelta: response.personScoresDelta,
          defaultValues: { reason: justification },
        })
        qualityScoreWarningOverlay.open()
        return
      }

      // If no warning needed, proceed with delete
      await performDelete(newConclusion, scoreChange)
    } catch (error) {
      // If validation fails, proceed with delete (graceful degradation)
      await performDelete(newConclusion)
    }
  }

  const suggestedReasonProps = {
    type: getDeleteSuggestedReasonsType(conclusion.type),
    personId,
  }

  const updateFooter = useOverlayUpdate('footer')
  useEffect(() => {
    updateFooter(() => <DeleteConclusionViewFooter deleteLabel={deleteLabel} deleting={deleting} />)
  }, [deleteLabel, deleting, updateFooter])

  return (
    <>
      <ReasonForm
        onSubmit={onSubmit}
        loading={deleting}
        label={t('conclusion.reason-for-deleting.label')}
        data-testid="conclusion:delete:reason"
        suggestedReasonProps={suggestedReasonProps}
      />

      {qualityScoreWarningProps?.personScoresDelta && (
        <>
          {isQualityScoreWarningDialogV2On ? (
            <QualityScoreWarningDialogV2
              personName={personName ?? ''}
              overlay={qualityScoreWarningOverlay}
              defaultValues={qualityScoreWarningProps?.defaultValues}
              personScoresDelta={qualityScoreWarningProps.personScoresDelta}
              onSave={onQualityScoreWarningSaveV2}
              onCancel={onQualityScoreWarningCancel}
              conclusionType={conclusion.type}
              actionType="Delete"
            />
          ) : (
            <QualityScoreWarningDialog
              overlay={qualityScoreWarningOverlay}
              personScoresDelta={qualityScoreWarningProps.personScoresDelta}
              onSave={onQualityScoreWarningSave}
              onCancel={onQualityScoreWarningCancel}
              conclusionType={conclusion.type}
              actionType="Delete"
            />
          )}
        </>
      )}
    </>
  )
}
