import React, { type ComponentProps } from 'react'
import { Button } from '@fs/zion-ui'
import { useTranslation } from 'react-i18next'
import { ContentEdit } from '@fs/zion-icon'

type EditButtonProps = {
  disabled?: boolean
  noShrinkX?: boolean
} & Omit<ComponentProps<typeof Button>, 'children'>

export default function EditButton(props: EditButtonProps): JSX.Element {
  const [t] = useTranslation()
  return (
    <Button Icon={ContentEdit} data-testid="ConclusionDialog:edit:button" noScrollTop {...props}>
      {t('common-ui:edit.action')}
    </Button>
  )
}
