import { useZionAxios as useZionAxiosUnTyped } from '@fs/zion-axios'
import { useEffectiveUser } from '@fs/zion-user'
import { useEffect, useState, useCallback } from 'react'
import { useStatusOverlay } from '@fs/zion-ui'
import { useTranslation } from 'react-i18next'
import type { EventDate, EventPlace, PersonId, VitalEventConclusion, WrappedResponse } from '@fs/zion-tree-types'
import type { UseAxios as UseAxiosTyped } from '@fs/zion-tree-types/zion-axios'

const useZionAxios = useZionAxiosUnTyped as UseAxiosTyped

const createConclusionText = ({ date, place }: { date?: EventDate; place?: EventPlace }): string =>
  `Date: ${date?.normalizedText || date?.originalText || 'No date provided'}, Place: ${
    place?.normalizedText || place?.originalText || 'No place provided'
  }`

type CreateCaseData = WrappedResponse<{ caseId: string; caseNumber: null; description: string; subject: string }>

type CreateCaseExecute = ({
  personId,
  personName,
  currentDeathConclusion,
  justification,
}: {
  personId: PersonId
  personName?: string
  currentDeathConclusion: VitalEventConclusion
  justification: string
}) => ReturnType<ReturnType<typeof useZionAxios<CreateCaseData, string>>[1]>

export const useCreateSupportCase = (): [
  ReturnType<typeof useZionAxios<CreateCaseData, string>>[0],
  CreateCaseExecute,
] => {
  const headers = {
    'Content-Type': 'text/plain',
  }
  const { country } = useEffectiveUser()
  const [responseStatus, execute] = useZionAxios<CreateCaseData, string>({ method: 'post', headers }, { manual: true })

  const callExecute: CreateCaseExecute = useCallback(
    ({ personId, personName, currentDeathConclusion, justification = '' }) => {
      const url = `/service/tree/tree-data/support/create-case?personName=${personName}&caseEntity=${personId}&requestType=Dead to Living Request&countryCode=${country}`
      const data = `
  Name of Person: ${personName}
  PID: ${personId}
  Current Death Conclusion: ${createConclusionText(currentDeathConclusion.details)}
  Current Death Justification: ${currentDeathConclusion.justification ?? 'No justification provided'}
  Living Request Justification: ${justification}
  `
      return execute({ url, data })
    },
    [country, execute]
  )

  return [responseStatus, callExecute]
}

export const useHasSupportCase = (personId: PersonId, close: () => void): { loading: boolean; hasCase: boolean } => {
  const [urlLoading, setUrlLoading] = useState(true)
  const [hasCase, setHasCase] = useState(false)
  const { cisId } = useEffectiveUser()
  const url = `/service/tree/tree-data/support/issues/exists?cisId=${cisId}&subject=${personId}&issueType=DEAD_TO_LIVING`
  const [{ loading: responseLoading }, execute] = useZionAxios<''>({ url }, { manual: true })
  const showStatusOverlay = useStatusOverlay()
  const { t } = useTranslation()

  useEffect(() => {
    if (cisId && urlLoading) {
      execute()
        .then(({ status }) => {
          setHasCase(status === 200)
        })
        .catch(() => {
          showStatusOverlay({ type: 'error', message: t('conclusion.ERROR_SAVE_FAILED') })
          close()
        })
      setUrlLoading(false)
    }
  }, [cisId, close, execute, showStatusOverlay, t, urlLoading])
  return { loading: responseLoading || urlLoading, hasCase }
}
