import { css, cx } from '@linaria/core'
import { type ConclusionScore } from '@fs/zion-person-quality-score-issues'
import { type ToLocation } from '@fs/zion-tree-types/zion-router'
import { useEvent } from '@fs/zion-frontend-friends'
import { type SourceListProps } from '@fs/zion-tree-types/zion-source-list'
import { splunk } from '@fs/zion-splunk-logger'
import ReasonConfirmDialog from './ReasonConfirmDialog'
import DeadToLivingDialog from './DeadToLivingDialog'
