import type { PersonId } from '@fs/zion-tree-types'
import { countsCacheService } from './caches'

export default function getContributorCount(personId: PersonId): Promise<number> {
  const url = `/service/tree/tree-data/impedance/person/${personId}`
  return countsCacheService.get<{ changeCount: number; contributorCount: number; pageCount: number }, number>(
    url,
    `${personId}:ContributorCount`,
    { preCacheHook: (data) => data.contributorCount }
  )
}
