import type { FieldValues, FieldPath } from '@fs/zion-form'
import type useSyncFieldToStorage from './useSyncFieldToStorage'
import useSyncDialogFieldsToStorage from './useSyncDialogFieldsToStorage'

type RemoveStoredFieldFunction = () => Promise<void>

type Props<TFieldValues extends FieldValues = FieldValues> = Pick<
  Parameters<typeof useSyncDialogFieldsToStorage<TFieldValues>>[0],
  'isOpen' | 'storeName' | 'methods'
> &
  Omit<Parameters<typeof useSyncFieldToStorage<TFieldValues>>[0], 'canUpdateStorage'> & {
    fieldName: FieldPath<TFieldValues>
  }

// This version of the hook handles clearing storage when the dialog is closed by the user intentionally (cancel button, click-away, close button, submit, whatever)
export default function useSyncDialogFieldToStorage<TFieldValues extends FieldValues = FieldValues>({
  isOpen,
  methods,
  fieldName,
  databaseKey,
  storeName,
  defaultText,
  defaultValue: defaultValueProp,
}: Props<TFieldValues>): RemoveStoredFieldFunction {
  return useSyncDialogFieldsToStorage<TFieldValues>({
    isOpen,
    storeName,
    baseDatabaseKey: databaseKey,
    methods,
    fieldNamesAndDefaults: [
      {
        name: fieldName,
        defaultValue: defaultValueProp ?? defaultText,
      },
    ],
  })
}
