import {
  Button,
  Separator,
  DialogOverlay,
  DialogOverlayFooter,
  DialogOverlayActions,
  type UseOverlayReturnOptions,
} from '@fs/zion-ui'
import React from 'react'
import { useTranslation } from 'react-i18next'
import { NoticeLoading } from '@fs/zion-icon'
import ZionForm, { useZionForm, FormMultilineTextField } from '@fs/zion-form'
import { useSyncDialogFieldToStorage } from '@fs/zion-storage-sync'
import type { Issue } from '../types/scores'
import IssueImprovement from './IssueImprovement'

type FormValues = {
  reasonStatement: string
}

type Props = {
  dismissOverlay: UseOverlayReturnOptions
  handleDismiss: ({ reasonStatement }: { reasonStatement: string }) => void
  isDismissing: boolean
  issue: Issue
  /** Controls when stored form state is preserved. Defaults to dismissOverlay.isOpen. */
  storageIsOpen?: boolean
}

export function DismissDialog({
  dismissOverlay,
  handleDismiss,
  isDismissing,
  issue,
  storageIsOpen,
}: Props): JSX.Element {
  const [t] = useTranslation()
  const methods = useZionForm({ defaultValues: { reasonStatement: '' } })
  useSyncDialogFieldToStorage({
    fieldName: 'reasonStatement',
    databaseKey: `${issue.id}_dismissIssueReason`,
    storeName: 'treePersonDismissIssueR9',
    methods,
    isOpen: storageIsOpen ?? dismissOverlay.isOpen,
  })

  return (
    <DialogOverlay
      {...dismissOverlay}
      title={t('person-quality-score-issues.dismiss-reason.label')}
      closeOnClickAway={false}
      onSubmit={handleDismiss}
      data-testid="pqs-dismiss-form"
      as={ZionForm<FormValues>}
      methods={methods}
    >
      <IssueImprovement issue={issue} />
      <Separator size="xxs" />
      <FormMultilineTextField
        name="reasonStatement"
        maxLength={350}
        label={t('person-quality-score-issues.dismiss-reason.label')}
        placeholder={t('person-quality-score-issues.dismiss-reason-placeholder.description')}
        data-testid="reason-input"
      />
      <DialogOverlayFooter>
        <DialogOverlayActions>
          <Button data-testid="cancel-button" onClick={dismissOverlay.close}>
            {t('common-ui:cancel.action')}
          </Button>
          <Button
            data-testid="pqs-dismiss-issue"
            fullWidth
            emphasis="high"
            disabled={isDismissing}
            Icon={isDismissing ? NoticeLoading : undefined}
            type="submit"
          >
            {t('person-quality-score-issues.dismiss.action')}
          </Button>
        </DialogOverlayActions>
      </DialogOverlayFooter>
    </DialogOverlay>
  )
}
