import CacheService from '@fs/zion-cache-service'
import type CacheServiceType from '@fs/zion-tree-types/zion-cache-service'
import type { CacheServiceConfig } from '@fs/zion-tree-types/zion-cache-service'

export const countsCacheService = new CacheService({
  cache: { storeName: 'tree_impedanceCounts', type: 'session' },
  strategy: 'cache-first',
} satisfies CacheServiceConfig) as CacheServiceType

export const countsCacheAndNetworkService = new CacheService({
  cache: { storeName: 'tree_impedanceCounts', type: 'session' },
  strategy: 'cache-and-network',
} satisfies CacheServiceConfig<unknown, 'cache-and-network'>) as CacheServiceType<unknown, 'cache-and-network'>
