import React, { useState, useRef, useEffect, useCallback, type ComponentType } from 'react'
import { TransitioningDialogOverlay, DialogOverlayActions, useEscHandler } from '@fs/zion-ui'
import { Route, useLocation, useHistory, RouteToParentRouter } from '@fs/zion-router'
import { useTranslation } from 'react-i18next'
import type { AttributionProps, Conclusion as ConclusionObj, ConclusionType, CoupleId } from '@fs/zion-tree-types'
import type { UseOverlayReturnOptions } from '@fs/zion-ui'
import { type ConclusionScore, type Issue } from '@fs/zion-person-quality-score-issues'
import { type SourceListProps } from '@fs/zion-tree-types/zion-source-list'
import DeleteConclusionView from './DeleteConclusionView'
import ConclusionDetailsView from './ConclusionDetailsView'
import AddEditConclusionView from './AddEditConclusionView'
import EditButton from '../EditButton'
import LivingPersonDeathLikeMessageDialog from './LivingPersonDeathLikeMessageDialog'
import type { CommonConclusionProps } from '../types'
import type { Mode } from '../../types/conclusionMode'
import getFollowerCount from '../../data-service/getFollowerCount'
import getContributorCount from '../../data-service/getContributorCount'
import { getConclusionDeleteLabel, isDeathLikeConclusionType } from '../../helpers/helpers'
import Label from '../Label'

function EscHandler(): null {
  const history = useHistory()
  const { pathname } = useLocation()

  const handler = useCallback(() => {
    history.goBack()
  }, [history])

  useEscHandler({
    handler,
    enabled: pathname !== '/add' && history.index > 0, // this second condition is to prevent the case that the user enters the dialog from the edit button and gets locked in because there is no history to go back to
  })

  return null
}

type ConclusionDialogProps = CommonConclusionProps & {
  /** Conclusion object. Either conclusion or type must be present */
  conclusion?: ConclusionObj

  /** Overlay state object from useOverlay(). */
  overlay: UseOverlayReturnOptions

  /** The type of conclusion. Only required when running in 'add' mode. */
  type?: ConclusionType

  /** Callback that runs when the conclusion is updated/deleted/created. */
  onConclusionUpdate?: (conclusion: ConclusionObj) => void

  /** Callback that runs when the dialog is closed. */
  onClose?: () => void

  /** Determines what view the dialog will open to. */
  mode?: Mode

  /** CoupleId for adding to PubSub -- needed for adding relationship type for a parent-child relationship */
  coupleId?: CoupleId

  /** Minimum height of dialog; ignored for add mode */
  minHeight?: number

  /** Maximum height of dialog; ignored for add mode */
  maxHeight?: number

  forceReset?: boolean

  /** If true, the dialog will first warn user they are editing a high quality detail. */
  personScore?: number

  /** Both Score and personScore need to be passed in together */
  score?: ConclusionScore

  /** Issues associated to the conclusion */
  issues?: Issue[]

  /** Attribution component to render */
  AttributionComponent?: ComponentType<AttributionProps>

  /** SourceListComponent component to render */
  SourceListComponent?: ComponentType<SourceListProps>

  /** Callback when an issue is dismissed - for refetching scores */
  onIssueDismissed?: () => void
}

export default function ConclusionDialog({
  mode = 'view',
  overlay,
  readOnly,
  onClose,
  type,
  subtitle,
  coupleId,
  minHeight,
  maxHeight,
  forceReset,
  score,
  personScore,
  issues,
  AttributionComponent,
  SourceListComponent,
  onIssueDismissed,
  ...props
}: ConclusionDialogProps): JSX.Element | null {
  const [t] = useTranslation()
  const { conclusion, relationshipId, person, simple, onConclusionUpdate, contributorCounts, followerCounts } = props
  // We expect either a conclusion or a type to be passed in
  const conclusionType = (type || conclusion?.type)!
  const focusDetailsRef = useRef<HTMLDivElement>(null)
  const focusAddEditRef = useRef<HTMLInputElement>()

  const [contributorCount, setContributorCount] = useState(contributorCounts)
  const [followerCount, setFollowerCount] = useState(followerCounts)
  const [hasFetchedCounts, setHasFetchedCounts] = useState({ contributor: false, follower: false })

  useEffect(() => {
    let isCurrent = true
    if (person?.id && !subtitle) {
      if (contributorCounts === undefined) {
        getContributorCount(person.id)
          .then((count) => {
            if (isCurrent) setContributorCount(count)
          })
          .catch(console.error)
          .finally(() => {
            if (isCurrent) setHasFetchedCounts((prev) => ({ ...prev, contributor: true }))
          })
      }

      if (followerCounts === undefined) {
        getFollowerCount(person.id)
          .then((count) => {
            if (isCurrent) setFollowerCount(count)
          })
          .catch(console.error)
          .finally(() => {
            if (isCurrent) setHasFetchedCounts((prev) => ({ ...prev, follower: true }))
          })
      }
    }
    return () => {
      isCurrent = false
    }
  }, [contributorCounts, subtitle, followerCounts, person?.id])

  let initialEntries: [string]
  switch (mode) {
    case 'edit':
      initialEntries = ['/edit']
      break
    case 'add':
      initialEntries = ['/add']
      break
    case 'view':
    default:
      initialEntries = ['/details']
  }

  const [deleting, setDeleting] = useState(false)

  const [closeOnClickAway, setCloseOnClickAway] = useState(false)
  const deleteLabel = getConclusionDeleteLabel(t, conclusionType)

  const isDeathLike = isDeathLikeConclusionType(conclusionType)
  const isReadOnly = readOnly

  function updateCloseOnClickAway(value): void {
    setCloseOnClickAway(value)
  }

  // We don't show sources in simple mode, if it is the lifesketch, or if it is a lineage conclusion (biological, etc.), or if it is in add mode and not adding christening, birth, or burial.
  const showSources =
    !simple &&
    conclusionType !== 'LIFE_SKETCH' &&
    !/_LINEAGE/.test(conclusionType) &&
    !(mode === 'add' && conclusionType !== 'CHRISTENING' && conclusionType !== 'BIRTH' && conclusionType !== 'BURIAL')

  // If living and user goes to add a death-like conclusion, show the warning dialog instead
  if (mode === 'add' && person?.living && isDeathLike) {
    return <LivingPersonDeathLikeMessageDialog overlay={overlay} />
  }

  let dialogSize: 'xs' | 'sm' | 'md' | 'lg' | 'xl' | 'xxl' =
    !showSources && conclusionType !== 'LIFE_SKETCH' ? 'md' : 'xl'

  if (conclusionType === 'NAME' || conclusionType === 'ALTERNATE_NAME') {
    dialogSize = !showSources ? 'lg' : 'xxl'
  }

  return overlay.isOpen || overlay.transitioning ? (
    <TransitioningDialogOverlay
      {...overlay}
      size={dialogSize}
      initialEntries={initialEntries}
      title={<Label conclusionType={conclusionType} score={score?.combinedRawScore} isVerboseScore />}
      subtitle={
        subtitle ||
        (!person?.living && !simple && hasFetchedCounts.contributor && hasFetchedCounts.follower && (
          <>
            {followerCount !== undefined && t('conclusion.impedance-info.followers', { number: followerCount })}
            {/* `&nbsp;&#8226;&nbsp;` is space-bullet-space or " • " */}
            {followerCount !== undefined && contributorCount !== undefined && (
              <span aria-hidden="true">&nbsp;&#8226;&nbsp;</span>
            )}
            {contributorCount !== undefined &&
              t('conclusion.impedance-info.contributors', { number: contributorCount })}
          </>
        ))
      }
      closeOnClickAway={closeOnClickAway}
      onClose={onClose}
      data-testid="conclusion-dialog"
      minHeight={mode === 'add' ? undefined : (minHeight ?? maxHeight ?? 900)}
      maxHeight={mode === 'add' ? undefined : (maxHeight ?? minHeight ?? 900)}
    >
      {/* VIEW */}
      <Route
        path="/details"
        focusRef={focusDetailsRef}
        footer={
          conclusion?.type === 'LIFE_SKETCH' &&
          !isReadOnly && (
            <DialogOverlayActions>
              <EditButton linkName="Edit LIFE_SKETCH" to="/edit" noShrinkX />
            </DialogOverlayActions>
          )
        }
      >
        {person && conclusion && (
          <CloseOnClickAwayWrapper
            functionToExecute={() => {
              updateCloseOnClickAway(true)
            }}
          >
            <ConclusionDetailsView
              {...props}
              AttributionComponent={AttributionComponent}
              SourceListComponent={SourceListComponent}
              conclusion={conclusion}
              readOnly={isReadOnly}
              focusRef={focusDetailsRef}
              personId={person.id}
              showSources={showSources}
              score={score}
              personScore={personScore}
              issues={issues}
              onIssueDismissed={onIssueDismissed}
            />
          </CloseOnClickAwayWrapper>
        )}
      </Route>
      {/* ADD / EDIT */}
      <Route path={['/add', '/edit']} focusRef={focusAddEditRef}>
        <EscHandler />
        {person && (
          <CloseOnClickAwayWrapper
            functionToExecute={() => {
              updateCloseOnClickAway(false)
            }}
          >
            <AddEditConclusionView
              conclusion={conclusion}
              type={type}
              relationshipId={relationshipId}
              overlay={overlay}
              focusRef={focusAddEditRef}
              personBirth={person.birth}
              personId={person.id}
              personName={person.name ?? ''}
              personGender={person.gender}
              onConclusionUpdate={(updatedConclusion) => {
                onConclusionUpdate?.(updatedConclusion)
                overlay.close()
              }}
              personIsLiving={person.living}
              simple={simple}
              showSources={showSources}
              readOnly={readOnly}
              coupleId={coupleId}
              forceReset={forceReset}
              score={score}
              personScore={personScore}
              mePersonCisId={person.mePersonCisId}
              treeType={person.treeType}
              treeId={person.treeId}
              AttributionComponent={AttributionComponent}
              SourceListComponent={SourceListComponent}
            />
          </CloseOnClickAwayWrapper>
        )}
      </Route>
      {/* DELETE */}
      <Route path="/delete" title={deleteLabel}>
        <EscHandler />
        {/* will get this error (Cannot read property 'type' of undefined) if conclusion is undefined */}
        {conclusion && person && (
          <DeleteConclusionView
            conclusion={conclusion}
            relationshipId={relationshipId}
            personId={person.id}
            personName={person.name ?? ''}
            deleteLabel={deleteLabel}
            deleting={deleting}
            setDeleting={setDeleting}
            onDelete={overlay.close}
            coupleId={coupleId}
          />
        )}
      </Route>
      <Route path="*">
        <RouteToParentRouter />
      </Route>
    </TransitioningDialogOverlay>
  ) : null
}

function CloseOnClickAwayWrapper({ functionToExecute, children }): JSX.Element {
  useEffect(() => {
    functionToExecute()
  }, [functionToExecute])

  return <>{children}</>
}
