import type { FamilyMemberPerson, PersonId, WrappedResponse } from '@fs/zion-tree-types'
import { countsCacheAndNetworkService } from './caches'

export type SpouseCounts = { MALE: number; FEMALE: number }

export type SpouseItem = {
  hasChildren: false // We always get false even if there are children...
  spouse: FamilyMemberPerson
}

export default function getSpouseCounts(personId: PersonId): [Promise<SpouseCounts>, Promise<SpouseCounts>] {
  const url = `/service/tree/tree-data/pedigree/person/${personId}/spouses`
  return countsCacheAndNetworkService.get<WrappedResponse<SpouseItem[]>, SpouseCounts>(
    url,
    `${personId}:spouseCounts`,
    {
      axiosConfig: { transformResponse: transformSpouseItemToSpouseCounts },
    }
  )
}

export function transformSpouseItemToSpouseCounts(data: string): SpouseCounts {
  const dataParsed: WrappedResponse<SpouseItem[]> = JSON.parse(data)
  let spouseCounts = { MALE: 0, FEMALE: 0 }
  if (dataParsed.statuses?.[0]?.cause || dataParsed.status !== 'OK') {
    // handle failed wrapped response
    throw new Error(dataParsed.statuses?.[0]?.cause || dataParsed.status)
  }

  if (dataParsed.data) {
    spouseCounts = dataParsed.data.reduce((initial, spouse) => {
      if (spouse.spouse && spouse.spouse.gender) {
        initial[spouse.spouse.gender]++
      }
      return initial
    }, spouseCounts)
  }
  return spouseCounts
}
