import type { Conclusion } from '@fs/zion-tree-types'
import type { AxiosPromise, AxiosResponse } from '@fs/zion-tree-types/zion-axios'
import axios from '@fs/zion-axios'
import { events, publish } from '@fs/zion-tree-pubsub'
import { trackEvent } from '@fs/zion-analytics'
import { createConclusionUrl, getRelationshipType } from '../helpers/helpers'

/**
 * Update an existing conclusion.
 * @param {object} conclusion - The new conclusion to create, with the conclusion already in tree-data format
 * @param {string} personIdOrRelationshipId - the id of the person or relationship to save the conclusion to
 * @returns {Promise} that resolves with the newly created conclusion
 */
export default async function saveConclusion(
  conclusion: Conclusion,
  personIdOrRelationshipId: string,
  coupleId?: string,
  analytics = true
): Promise<AxiosResponse> {
  // With our current form architecture, we can assume we've already gone through validation, so we don't re-validate here
  const requestMethod = conclusion?.id ? 'put' : 'post'

  conclusion.justification = conclusion.justification?.trim() ?? ''
  analytics && trackEvent({ link_name: `${conclusion?.id ? 'Update' : 'Save'} ${conclusion.type} conclusion` })

  function checkWarning(response): void {
    if (response.headers.warning) {
      // Handle wrapped and unwrapped responses
      if (response.data) response.data = { data: response.data.data ?? response.data }
      else response.data = { data: response.data }
      response.data.status = 'BAD_REQUEST'
      if (!response.data.statuses) {
        response.data.statuses = []
        response.data.statuses.push({ code: response.headers.warning })
      }
      throw { response } // eslint-disable-line no-throw-literal -- We still want to use the response
    }
  }

  return (
    axios({
      method: requestMethod,
      url: createConclusionUrl(conclusion, personIdOrRelationshipId, requestMethod),
      data: saveNameConclusionAsUnd(conclusion),
      //  we will need a catch for association event types since they dont return wrapped responses
    }) as AxiosPromise
  )
    .then((response) => {
      checkWarning(response)
      if (response.data.status && response.data.status !== 'OK') {
        throw { response } // eslint-disable-line no-throw-literal -- We still want to use the response
      }
      // Handle wrapped and unwrapped responses
      const responseData = response.data.data ?? response.data
      const relationshipType = getRelationshipType(conclusion.type)
      const key = relationshipType ? 'relationshipId' : 'personId'
      const data = {
        action: requestMethod === 'post' ? 'add' : 'edit',
        conclusion: responseData,
        relationshipType,
        [key]: personIdOrRelationshipId,
        coupleId,
      }
      const evt = events.conclusion
      publish({ evt, data })
      return responseData
    })
    .catch((error) => {
      // If it wasn't wrapped, check for warnings
      if (!error.response?.data?.status) checkWarning(error.response)
      throw error
    })
}

function saveNameConclusionAsUnd(conclusion: Conclusion): Conclusion {
  if (conclusion.type !== 'NAME') return conclusion
  const newConclusion = { ...conclusion }

  const newNameForms = newConclusion.details.nameForms?.map((nameForm) => {
    if (nameForm.lang === 'x-Latn' || nameForm.lang === 'und-Latn') {
      return { ...nameForm, lang: 'und' }
    }
    return nameForm
  })
  return { ...conclusion, details: { ...conclusion.details, nameForms: newNameForms } }
}
