import zionDebug from '@fs/zion-debug'
import type ZionCache from '@fs/zion-tree-types/zion-cache'

export const debug = zionDebug('treeWeb:storageSync')

type UpdateStorageItemProps = {
  /** The Zion Cache */
  cache: ZionCache<string | boolean | string[]>
  /** Value to set for database key */
  value: string | boolean | string[] | null
  /** Database key for Zion Cache */
  key?: string
}

export const updateStorageItem = ({ cache, value, key }: UpdateStorageItemProps): Promise<void> => {
  debug(`Value is '${value}'.\ndatabaseKey=${key}`)

  if (value !== null && value !== '' && !(Array.isArray(value) && value.length === 0) && key) {
    debug(`Setting the deserialized value of '${JSON.stringify(value)}' in the cache.\ndatabaseKey=${key}`)
    return cache.setItem(key, value).catch(console.error)
  }

  if ((value === '' || (Array.isArray(value) && value.length === 0) || value === false) && key) {
    debug(`Removing value in the cache.\ndatabaseKey=${key}`)
    return cache.removeItem(key).catch(console.error)
  }

  return Promise.resolve()
}
