import { type Dispatch, type SetStateAction } from 'react'
import { useStatusOverlay } from '@fs/zion-ui'
import { useTranslation } from 'react-i18next'
import { trackEvent } from '@fs/zion-analytics'
import type {
  Conclusion,
  ConclusionType,
  CoupleId,
  EventDate,
  Gender,
  PersonId,
  TreeType,
  VitalEventConclusion,
} from '@fs/zion-tree-types'
import { useLocation } from '@fs/zion-router'
import type { UseOverlayReturnOptions } from '@fs/zion-ui'
import { useEvent } from '@fs/zion-frontend-friends'
import { useFeatureFlag } from '@fs/zion-flags'
import type { FormValues } from '../../types/form'
import type { PersonScoresDelta } from '../../types/qualityScore'
import { convertFormDataToTreeData } from '../../helpers/helpers'
import deleteConclusion from '../../data-service/deleteConclusion'
import saveConclusion from '../../data-service/saveConclusion'
import validateConclusionQuality from '../../data-service/validateConclusionQuality'

type SubmitProps = {
  values: FormValues
  alreadyOpenSecondDialog: boolean
  mePersonCisId?: string
  treeType?: TreeType
}

type Props = {
  conclusion?: Conclusion
  type?: ConclusionType
  personId: PersonId
  relationshipId?: string
  onConclusionUpdate?: (conclusion: Conclusion) => void
  personIsLiving?: boolean
  simple?: boolean
  personBirth?: VitalEventConclusion
  reasonConfirmOverlay: UseOverlayReturnOptions
  deadToLivingOverlay: UseOverlayReturnOptions
  areYouSurePersonIsDeceasedOverlay: UseOverlayReturnOptions
  fgtMarkPersonDeceasedOverlay: UseOverlayReturnOptions
  qualityScoreWarningOverlay: UseOverlayReturnOptions
  setLoading: Dispatch<SetStateAction<boolean>>
  setQualityScoreValidationScoresDelta?: Dispatch<SetStateAction<PersonScoresDelta | undefined>>

  /** CoupleId for adding to PubSub -- needed for adding relationship type for a parent-child relationship */
  coupleId?: CoupleId
}

export const calculateScoreChange = (currentScore: number | undefined, newScore: number | undefined): string => {
  const getScoreLevel = (score: number | undefined): string => {
    if (score === undefined) return 'not available'
    if (score >= 0.85) return 'high'
    if (score >= 0.31) return 'medium'
    return 'low'
  }

  const currentLevel = getScoreLevel(currentScore)
  const newLevel = getScoreLevel(newScore)

  return `${currentLevel}->${newLevel}`
}

export default function useHelperFunctions({
  // Pass through
  type,
  relationshipId,
  personId,
  onConclusionUpdate,
  conclusion,
  simple,
  personIsLiving,
  personBirth,
  coupleId,
  // From parent
  deadToLivingOverlay,
  setLoading,
  reasonConfirmOverlay,
  areYouSurePersonIsDeceasedOverlay,
  fgtMarkPersonDeceasedOverlay,
  qualityScoreWarningOverlay,
  setQualityScoreValidationScoresDelta,
}: Props): {
  handleError: (error: unknown, personSex: Gender) => void
  saveConclusionForReal: (
    newConclusion: Conclusion,
    values: FormValues,
    oldConclusion: Conclusion | undefined
  ) => Promise<void>
  handleQualityValidationAndSave: (
    newConclusion: Conclusion,
    values: FormValues,
    oldConclusion: Conclusion | undefined
  ) => Promise<void>
  chooseOnSubmit: (props: SubmitProps) => void
} {
  const [t] = useTranslation()
  const showStatusOverlay = useStatusOverlay()
  const location = useLocation()
  const routeStateCoupleId = location.state?.coupleId
  const qualityScoreWarningFlagIsOn = useFeatureFlag('treeWeb_conclusion_pqsWarning').isOn

  // Helper function to check if conclusion type is vital
  const isVitalConclusionType = (conclusionType: ConclusionType): boolean => {
    const vitalTypes: ConclusionType[] = ['BIRTH', 'DEATH', 'CHRISTENING', 'BURIAL', 'GENDER', 'NAME']
    return vitalTypes.includes(conclusionType)
  }

  // eslint-disable-next-line @typescript-eslint/no-explicit-any -- when we have no more wrapped responses, we should change error back to unknown and using isAxiosError etc
  const handleError = useEvent((error: any, personSex: string): void => {
    const status = error?.response?.data?.status ?? error?.status
    const statuses = error?.response?.data?.statuses ?? error?.statuses
    const warning = statuses?.[0]?.code || ''

    /*
        List of possible TF response codes:
        https://github.com/fs-eng/tf/blob/master/event-builders/src/main/java/org/familysearch/tf/builders/exception/WarningSubCodeType.java
      */
    switch (status) {
      case 'BAD_REQUEST':
        if (type === 'GENDER' && personSex === 'UNKNOWN') {
          showStatusOverlay({
            message: t('conclusion.ERROR_SAVE_UNKNOWN_GENDER_FAILED'),
            type: 'error',
          })
          break
        }
        if (warning.includes('301')) {
          // Duplicate on Edit
          showStatusOverlay({
            message: t('conclusion.ERROR_DUPLICATE_SAVE_FAILED'),
            type: 'error',
          })
          break
        }
        if (warning.includes('310')) {
          // Race condition
          showStatusOverlay({
            message: t('conclusion.ERROR_RACE_CONDITION_SAVE_FAILED'),
            type: 'error',
          })
          break
        }
        if (warning.includes('416')) {
          // Editing self
          showStatusOverlay({
            message: t('conclusion.ERROR_CANNOT_MARK_SELF_DECEASED'),
            type: 'error',
          })
          break
        }
        if (warning.includes('435')) {
          // Disallowed characters
          showStatusOverlay({
            message: t('conclusion.ERROR_DISALLOWED_CHARACTERS'),
            type: 'error',
          })
          break
        }
        if (warning.includes('433')) {
          // Death-like dates (death, burial, cremation) cannot be in future
          showStatusOverlay({
            message: t('conclusion.ERROR_CANNOT_HAVE_FUTURE_DEATHLIKE_DATE'),
            type: 'error',
          })
          break
        }
        showStatusOverlay({ message: t('conclusion.ERROR_SAVE_FAILED'), type: 'error' })
        break
      case 'NOT_FOUND':
        showStatusOverlay({
          message: t('conclusion.ERROR_404'),
          type: 'error',
        })
        break
      case 'CONFLICT':
        showStatusOverlay({
          message: t('conclusion.ERROR_409'),
          type: 'error',
        })
        break
      case 'NOT_AUTHORIZED': {
        if (warning.includes('706') || warning.includes('705')) {
          deadToLivingOverlay.open()
        }
        break
      }
      case 403: // The relationship or one of the referenced persons is restricted from the user
      case 410: // Relationship is restricted from the user
      default:
        showStatusOverlay({ message: t('conclusion.ERROR_SAVE_FAILED'), type: 'error' })
    }
  })

  const saveConclusionForReal = useEvent(
    (
      newConclusion: Conclusion,
      values: Record<string, unknown>,
      oldConclusion: Conclusion | undefined,
      scoreChange?: string
    ): Promise<void> => {
      setLoading(true)
      const raisingFromTheDead = newConclusion.type === 'DEATH' && values.living === 'LIVING'
      const method = raisingFromTheDead ? deleteConclusion : saveConclusion
      return method(newConclusion, relationshipId || personId, coupleId || routeStateCoupleId, false)
        .then(() => {
          onConclusionUpdate?.(newConclusion)
          if (!raisingFromTheDead) {
            let link_name = `${newConclusion?.id ? 'Update' : 'Save'} ${newConclusion.type} conclusion`
            if (newConclusion?.type === 'LIFE_SKETCH' && oldConclusion?.type === 'LIFE_SKETCH') {
              if (newConclusion.id) {
                if (oldConclusion?.details?.userCertified && !newConclusion.details.userCertified)
                  link_name = 'Update LIFE_SKETCH conclusion: Published -> Not Published'
                else if (!oldConclusion?.details?.userCertified && newConclusion.details.userCertified)
                  link_name = 'Update LIFE_SKETCH conclusion: Not Published -> Published'
              } else if (newConclusion.details.userCertified) {
                link_name = 'Save LIFE_SKETCH conclusion: Published'
              }
            }

            trackEvent({
              link_name,
              quality_score_saved: scoreChange,
            })
          }
        })
        .catch((error) => {
          handleError(error, values?.sex as Gender)
          setLoading(false)
        })
    }
  )

  const handleQualityValidationAndSave = useEvent(
    async (newConclusion: Conclusion, values: FormValues, oldConclusion: Conclusion | undefined): Promise<void> => {
      // Set loading state immediately when save is initiated
      setLoading(true)

      // Validate for vital types even when flag iss off. We want to know scores even when the flag is off
      const shouldValidateQualityScore = isVitalConclusionType(newConclusion.type)

      if (!shouldValidateQualityScore) {
        // no quality info to send
        await saveConclusionForReal(newConclusion, values, oldConclusion)
        return
      }

      try {
        const { shouldWarn, response } = await validateConclusionQuality({
          personId,
          conclusionToEdit: oldConclusion,
          conclusionToAdd: newConclusion,
        })
        const delta = response?.personScoresDelta
        // We want to track if we are going from a higher Person Quality Score to a lower one, or we are rather improving it
        const scoreChange = calculateScoreChange(
          delta?.currentScores?.overallRawScore,
          delta?.newScores?.overallRawScore
        )
        if (qualityScoreWarningFlagIsOn && shouldWarn && response) {
          setLoading(false)
          setQualityScoreValidationScoresDelta?.(response.personScoresDelta)
          qualityScoreWarningOverlay.open()
          return
        }

        // If no warning needed, proceed with save
        await saveConclusionForReal(newConclusion, values, oldConclusion, scoreChange)
      } catch (error) {
        // If quality validation fails, continue with save (don't block the user)
        await saveConclusionForReal(newConclusion, values, oldConclusion)
      }
    }
  )

  const definedType = (conclusion?.type || type)!

  const chooseOnSubmit = useEvent(({ values, alreadyOpenSecondDialog, mePersonCisId, treeType }: SubmitProps) => {
    const newConclusion = convertFormDataToTreeData(values, { type: definedType, id: conclusion?.id })
    const livingPersonChangingToDeceasedPerson =
      newConclusion.type === 'DEATH' && values.living === 'DECEASED' && personIsLiving
    if (
      mePersonCisId &&
      livingPersonChangingToDeceasedPerson &&
      treeType === 'SHARED_FAMILY_GROUP' &&
      !alreadyOpenSecondDialog
    ) {
      fgtMarkPersonDeceasedOverlay.open()
      return
    }
    if (!alreadyOpenSecondDialog && livingPersonChangingToDeceasedPerson) {
      const deathDateConclusion = newConclusion?.details?.date
      const birthDateConclusion = personBirth?.details?.date
      const todaysYear = new Date()?.getFullYear()
      const deathYear = getDateYearValue(deathDateConclusion)
      const birthYear = getDateYearValue(birthDateConclusion)
      if ((!birthYear && deathYear && todaysYear - deathYear <= 110) || (birthYear && todaysYear - birthYear <= 110)) {
        areYouSurePersonIsDeceasedOverlay.open()
        return
      }
    }
    if (
      newConclusion.justification === conclusion?.justification &&
      Boolean(conclusion?.justification?.trim()) &&
      !simple
    ) {
      reasonConfirmOverlay.open()
      return
    }
    areYouSurePersonIsDeceasedOverlay.close()
    handleQualityValidationAndSave(newConclusion, values, conclusion)
  })
  return { handleError, saveConclusionForReal, handleQualityValidationAndSave, chooseOnSubmit }
}

function getDateYearValue(conclusionDate: EventDate | undefined): number | undefined {
  const dateString = conclusionDate?.formalText || conclusionDate?.normalizedText || conclusionDate?.originalText
  return dateString ? new Date(dateString)?.getFullYear() : undefined
}
