import React, { useRef } from 'react'
import { DialogOverlay, DialogOverlayActions, Button, Paragraph, Row } from '@fs/zion-ui'
import { useTranslation } from 'react-i18next'
import type { UseOverlayReturnOptions } from '@fs/zion-ui'

type ReasonConfirmDialogProps = {
  overlay: UseOverlayReturnOptions
  onConfirm: () => void
}

export default function ReasonConfirmDialog({ overlay, onConfirm }: ReasonConfirmDialogProps): JSX.Element {
  const [t] = useTranslation()
  const yesRef = useRef<HTMLButtonElement>(null)
  return (
    <DialogOverlay {...overlay} focusRef={yesRef} title={t('conclusion.edit.reason-not-changed.header')}>
      <Paragraph size="sm">{t('conclusion.edit.reason-not-changed.body')}</Paragraph>

      <DialogOverlayActions>
        <Row>
          <Button data-testid="cleanReasonNoButton" onClick={overlay.close}>
            {t('common-ui:no.action')}
          </Button>

          <Button ref={yesRef} data-testid="cleanReasonYesButton" type="submit" emphasis="high" onClick={onConfirm}>
            {t('common-ui:yes.action')}
          </Button>
        </Row>
      </DialogOverlayActions>
    </DialogOverlay>
  )
}
