import React from 'react'
import { useTranslation } from 'react-i18next'
import { Button } from '@fs/zion-ui'
import type { Conclusion, PersonId } from '@fs/zion-tree-types'
import { getChangelogLink } from '../helpers/helpers'

type SeeAllChangesLinkProps = {
  /** Which conclusion the link to will point to in the changelog. */
  conclusion: Conclusion

  /** Person ID this conclusion belongs to. */
  personId: PersonId

  /** Relationship ID this conclusion belongs to (if applicable). */
  relationshipId?: string
}

export default function SeeAllChangesLink({
  conclusion,
  personId,
  relationshipId,
}: SeeAllChangesLinkProps): JSX.Element {
  const { type } = conclusion
  const [t] = useTranslation()
  const changelogLink = getChangelogLink({ type, personId, relationshipId })

  return (
    <Button
      data-testid="ConclusionDetail:see-all-changes:link"
      to={window.location.origin + changelogLink}
      external
      target="_blank"
    >
      {t('conclusion.see-all-changes.link')}
    </Button>
  )
}
