import React, { forwardRef } from 'react'
import { cx } from '@linaria/core'
import { sanitizeProps } from '@fs/zion-frontend-friends'
import { useFeatureFlag } from '@fs/zion-flags'
import TextAndIconButton from '../TextAndIconButton'
import { colorCss, highCss, highNightCss } from '../colorStyles'
import { highEmphasisCss } from '../emphasisStyles'
import { dangerTheme, useTheme } from '../../theme'
import type { TextAndIconButtonProps } from '../types'
import { buttonCss, lowercaseButtonCss } from '../button/Button'
import { textBcss } from '../../typography/typographyStyles'

/**
 * ### _A button to be used for potentially destructive actions_
 *
 * The Danger Button should be used as the button to confirm a destructive action
 * that will result in the user losing data. Affordances that remove data yet keep
 * it archived and indefinitely retrievable should not use the Danger button.
 */

const DangerButton = forwardRef(
  ({ fullWidth, children, ...props }: Omit<TextAndIconButtonProps, 'className' | 'iconSize'>, ref) => {
    const theme = useTheme()
    const { isOn: lowercaseButton } = useFeatureFlag('frontier_zionui_lowercase_button')
    const classNames = [
      lowercaseButton ? lowercaseButtonCss : buttonCss,
      colorCss,
      textBcss,
      theme === 'day' ? highCss : highNightCss,
      highEmphasisCss,
      dangerTheme,
    ]

    return (
      <TextAndIconButton
        {...sanitizeProps(props)}
        fullWidth={fullWidth}
        iconSize="xs"
        className={cx(...classNames)}
        ref={ref}
      >
        {children}
      </TextAndIconButton>
    )
  }
)

export default DangerButton
