import React, { type Ref, useState, type ComponentProps, type ComponentType } from 'react'
import { Alert, Cell, Grid, List, MarginBox, Row, useContainerWidth } from '@fs/zion-ui'
import type { AttributionProps, Conclusion as ConclusionObj, PersonId } from '@fs/zion-tree-types'
import { type ConclusionScore, type Issue, IssueImprovement } from '@fs/zion-person-quality-score-issues'
import { useTranslation } from 'react-i18next'
import ErrorBoundary from '@fs/zion-error-boundary'
import { type SourceListProps } from '@fs/zion-tree-types/zion-source-list'
import { useFeatureFlag } from '@fs/zion-flags'
import { trackEvent } from '@fs/zion-analytics'
import SeeAllChangesLink from '../SeeAllChangesLink'
import RenderTheSketch from '../RenderTheSketch'
import EditButton from '../EditButton'
import SplitDialogContent from './SplitDialogContent'
import ConclusionSourceList from './ConclusionSourceList'
import ExpandContentSwitch from './ExpandContentSwitch'
import useShouldWarn from '../../helpers/useShouldWarn'
import ConclusionBase from '../ConclusionBase'

type ConclusionDetailsViewProps = {
  conclusion: ConclusionObj
  personId: PersonId
  relationshipId?: string
  simple?: boolean
  readOnly?: boolean
  focusRef?: Ref<HTMLDivElement>
  editPath?: ComponentProps<typeof EditButton>['to']
  showSources?: boolean
  inline?: boolean
  score: ConclusionScore | undefined
  personScore: number | undefined
  issues?: Issue[]
  AttributionComponent?: ComponentType<AttributionProps>
  SourceListComponent?: ComponentType<SourceListProps>
  /** Callback when an issue is dismissed - for refetching scores */
  onIssueDismissed?: () => void
}

type ConclusionDetailsViewWithoutScoresProps = Omit<ConclusionDetailsViewProps, 'score' | 'personScore'> &
  Partial<{
    score: never
    personScore: never
  }>

export default function ConclusionDetailsView({
  conclusion,
  personId,
  relationshipId,
  simple,
  readOnly,
  focusRef,
  editPath = '/edit',
  showSources = false,
  inline,
  score,
  personScore,
  issues,
  AttributionComponent,
  SourceListComponent,
  onIssueDismissed,
}: ConclusionDetailsViewProps | ConclusionDetailsViewWithoutScoresProps): JSX.Element {
  const [t] = useTranslation()
  const [expandContent, setExpandContent] = useState<boolean>(false)
  const showPqsWarningDialogV2 = useFeatureFlag('treeWeb_conclusion_pqsWarningDialogV2').isOn
  const atWidth = useContainerWidth()
  const isMobile = atWidth({ default: true, md: false })
  const shouldWarn = useShouldWarn(personScore ?? 0, score?.combinedRawScore ?? 0)
  const customLinkName = shouldWarn
    ? `Edit ${conclusion.type} from Dialog: Impedance Score ${score?.combinedRawScore?.toFixed(1)}`
    : `Edit ${conclusion.type} from Dialog`

  const issueImprovementDismissedProps =
    onIssueDismissed && personId !== 'UNKNOWN'
      ? {
          onDismissed: (issueId: string) => {
            trackEvent({
              event_name: 'conclusion_details_issue_dismissed',
              issue_id: issueId,
              conclusion_type: conclusion.type,
            })
            onIssueDismissed()
          },
          personId,
        }
      : {}

  const showHighQualityImpedanceWarning = shouldWarn && !showPqsWarningDialogV2

  return (
    <SplitDialogContent
      left={
        <Grid gutters="xs">
          {!isMobile && SourceListComponent && (
            <Row alignY="middle" wrap={false} gutters="none">
              <div growX />
              <ExpandContentSwitch expandContent={expandContent} setExpandContent={setExpandContent} />
            </Row>
          )}
          {showHighQualityImpedanceWarning && (
            <Alert type="warning">{t('conclusion.high-quality-impedance.warning')}</Alert>
          )}

          <Cell>
            {conclusion.type === 'LIFE_SKETCH' ? (
              <RenderTheSketch lifesketch={conclusion} focusRef={focusRef} />
            ) : (
              <Row data-testid="conclusionDetailOverlay:datablock">
                <MarginBox marginY="pico" growX>
                  <ConclusionBase
                    conclusion={conclusion}
                    showStandard
                    inline={inline}
                    data-testid={`conclusionDisplay:${conclusion.type}`}
                  />
                </MarginBox>
                <EditButton linkName={customLinkName} to={editPath} disabled={readOnly} noShrinkX />
              </Row>
            )}
            {!simple && (
              <>
                {AttributionComponent && (
                  <AttributionComponent
                    contributor={conclusion.contributor}
                    justification={conclusion.justification?.trim()}
                    headingLevel="div"
                  />
                )}
                <Grid gutters="nano">
                  <List data-testid="conclusion-issues-list">
                    {issues &&
                      issues.length > 0 &&
                      issues.map((issue) => (
                        <ErrorBoundary key={issue.id}>
                          <IssueImprovement issue={issue} {...issueImprovementDismissedProps} />
                        </ErrorBoundary>
                      ))}
                  </List>
                  <SeeAllChangesLink conclusion={conclusion} personId={personId} relationshipId={relationshipId} />
                </Grid>
              </>
            )}
          </Cell>
        </Grid>
      }
      right={
        showSources && SourceListComponent ? (
          <ConclusionSourceList
            conclusion={conclusion}
            personId={personId}
            relationshipId={relationshipId}
            readOnly={readOnly}
            SourceListComponent={SourceListComponent}
          />
        ) : null
      }
      fullColumns={expandContent}
    />
  )
}
