import axiosUntyped from '@fs/zion-axios'
import type axios from '@fs/zion-tree-types/zion-axios'
import { type AxiosResponse } from '@fs/zion-tree-types/zion-axios'

const axiosTyped = axiosUntyped as typeof axios

/**
 * Dismiss a quality score issue for a person
 * 201 - The request completed successfully.
 * 401 - The session is unauthenticated or has expired.
 * 404 - Unknown person ID.
 */
export default function dismissIssue({
  personId,
  issueId,
  reason,
}: {
  personId: string
  issueId: string
  reason: string
}): Promise<AxiosResponse<''>> {
  return axiosTyped.post<''>(`/service/tree/tree-data/quality/person/${personId}/dismissed-issues/${issueId}`, {
    reason,
  })
}
