import { useEffect, useMemo, useRef, useState } from 'react'
import Cache from '@fs/zion-cache'
import type { UseZionFormReturn, FieldValues, FieldPath, PathValue, FieldPathValue } from '@fs/zion-form'
import { useWatch } from '@fs/zion-form'
import type ZionCache from '@fs/zion-tree-types/zion-cache'
import { debug, updateStorageItem } from '../helpers'

type RemoveStoredFieldsFunction = () => Promise<void>

type Props<TFieldValues extends FieldValues = FieldValues> = {
  /** Array of Zion Form field names to sync with the option to specify the default value for each field name. */
  fieldNamesAndDefaults: (
    | FieldPath<TFieldValues>
    | {
        name: FieldPath<TFieldValues>
        defaultValue: PathValue<TFieldValues, FieldPath<TFieldValues>> | undefined | null
      }
  )[]
  /** Base database key that will be combined with field names. Ex: KW39-ABCD:relationship:edit */
  baseDatabaseKey?: string
  /** Unique name for storing temp data. Ex: treePersonR9Relationship */
  storeName: string
  /** Methods from useZionForm */
  methods: Pick<UseZionFormReturn<TFieldValues>, 'control' | 'setValue' | 'resetField'>
  /** If the values from fieldNames should be stored */
  canUpdateStorage?: boolean
}

export default function useSyncFieldsToStorage<TFieldValues extends FieldValues = FieldValues>({
  fieldNamesAndDefaults,
  baseDatabaseKey,
  storeName,
  methods: { control, setValue, resetField },
  canUpdateStorage = true,
}: Props<TFieldValues>): RemoveStoredFieldsFunction {
  const [readyToUpdateDatabaseKey, setReadyToUpdateDatabaseKey] = useState<string | undefined>()

  // Memoize just the field names (not the default values)
  const fieldNamesKey = useMemo(
    () => JSON.stringify(fieldNamesAndDefaults.map((field) => (typeof field === 'string' ? field : field.name))),
    [fieldNamesAndDefaults]
  )
  const memoizedFieldNames = useMemo(
    () => fieldNamesAndDefaults.map((field) => (typeof field === 'string' ? field : field.name)),
    // eslint-disable-next-line react-hooks/exhaustive-deps -- fieldNamesKey is used to detect actual field name changes
    [fieldNamesKey]
  )

  // Memoize default values separately
  const defaultValuesKey = useMemo(
    () =>
      JSON.stringify(
        fieldNamesAndDefaults.map((field) => (typeof field === 'string' ? undefined : field.defaultValue))
      ),
    [fieldNamesAndDefaults]
  )
  const memoizedDefaultValues = useMemo(
    () =>
      fieldNamesAndDefaults.reduce<Partial<Record<FieldPath<TFieldValues>, string | boolean | string[]>>>(
        (acc, field) => {
          if (typeof field !== 'string' && field.defaultValue != null) {
            acc[field.name] = field.defaultValue
          }
          return acc
        },
        {}
      ),
    // eslint-disable-next-line react-hooks/exhaustive-deps -- defaultValuesKey is used to detect default value changes
    [defaultValuesKey]
  )

  // Watch all fields
  const values = useWatch({
    control,
    name: memoizedFieldNames,
  })

  const cache: ZionCache<string | boolean | string[]> = useMemo(() => {
    debug(`Cache made with storeName=${storeName}`)
    return new Cache({ storeName })
  }, [storeName])

  // Use ref to always have access to current default values
  const defaultValuesRef = useRef(memoizedDefaultValues)
  useEffect(() => {
    defaultValuesRef.current = memoizedDefaultValues
  }, [memoizedDefaultValues])

  // Use ref to always have access to current values in the cleanup function
  const currentValuesRef = useRef({ baseDatabaseKey, memoizedFieldNames, cache, storeName })
  useEffect(() => {
    currentValuesRef.current = { baseDatabaseKey, memoizedFieldNames, cache, storeName }
  }, [baseDatabaseKey, memoizedFieldNames, cache, storeName])

  useEffect(() => {
    debug(`Not ready to update baseDatabaseKey=${baseDatabaseKey}`)
    // Whenever the baseDatabaseKey changes, don't update the database until we have gotten the first stored values
    setReadyToUpdateDatabaseKey(undefined)
  }, [baseDatabaseKey])

  // Set default values synchronously when baseDatabaseKey changes (before loading from storage)
  // This ensures fields show the correct value immediately, just like useSyncFieldToStorage does
  // Only depends on baseDatabaseKey to avoid re-running while user is typing
  useEffect(() => {
    const currentDefaults = defaultValuesRef.current
    memoizedFieldNames.forEach((fieldName) => {
      const defaultValue = currentDefaults[fieldName]
      if (defaultValue) {
        debug(
          `Setting the default value of '${defaultValue}' for the field, ${fieldName}\nstoreName=${storeName}\nbaseDatabaseKey=${baseDatabaseKey}`
        )
        setValue(fieldName, defaultValue as FieldPathValue<TFieldValues, typeof fieldName>, {
          shouldValidate: true,
          shouldDirty: true,
        })
      }
    })
    // eslint-disable-next-line react-hooks/exhaustive-deps -- Only run when baseDatabaseKey changes
  }, [baseDatabaseKey])

  // Sync each field to storage using manual effect instead of useSyncToStorage hook
  useEffect(() => {
    if (!canUpdateStorage || !readyToUpdateDatabaseKey || readyToUpdateDatabaseKey !== baseDatabaseKey) {
      return
    }

    memoizedFieldNames.forEach((fieldName, index) => {
      const databaseKey = baseDatabaseKey ? `${baseDatabaseKey}:${fieldName}` : undefined
      const value = Array.isArray(values) ? values[index] : null
      updateStorageItem({ cache, value, key: databaseKey })
    })
  }, [values, baseDatabaseKey, cache, canUpdateStorage, readyToUpdateDatabaseKey, memoizedFieldNames, storeName])

  // Reset all fields when baseDatabaseKey changes
  useEffect(() => {
    debug(`Resetting fields for baseDatabaseKey=${baseDatabaseKey}`)
    memoizedFieldNames.forEach((fieldName) => {
      resetField(fieldName)
    })
  }, [resetField, baseDatabaseKey, memoizedFieldNames])

  // Load stored values for all fields, then apply defaults for fields without stored values
  // This should only run when baseDatabaseKey or field names change, NOT when defaults change
  useEffect(() => {
    let isCurrent = true
    debug(`Loading stored values for fields.\nstoreName=${storeName}\nbaseDatabaseKey=${baseDatabaseKey}`)

    if (baseDatabaseKey) {
      const loadPromises = memoizedFieldNames.map((fieldName) => {
        const databaseKey = `${baseDatabaseKey}:${fieldName}`
        return cache
          .getItem(databaseKey)
          .then((storedValue) => {
            debug(
              `The stored value for ${fieldName} is ${storedValue}.\nstoreName=${storeName}\ndatabaseKey=${databaseKey}`
            )
            if (storedValue !== null && isCurrent) {
              debug(
                `Setting the stored value of '${storedValue}' for the field, ${fieldName}.\nstoreName=${storeName}\ndatabaseKey=${databaseKey}`
              )
              setValue(fieldName, storedValue as FieldPathValue<TFieldValues, typeof fieldName>, {
                shouldValidate: true,
                shouldDirty: true,
              })
            }
          })
          .catch((error) => {
            console.error(error)
          })
      })

      Promise.all(loadPromises).then(() => {
        if (!isCurrent) return

        debug(`Ready to update baseDatabaseKey=${baseDatabaseKey}`)
        setReadyToUpdateDatabaseKey(baseDatabaseKey)
      })
    }

    return () => {
      isCurrent = false
    }
    // Only depend on baseDatabaseKey and field names, NOT on default values
    // This prevents re-loading when user changes defaults in the story controls
  }, [cache, baseDatabaseKey, memoizedFieldNames, setValue, storeName])

  return () => {
    const {
      baseDatabaseKey: currentKey,
      memoizedFieldNames: currentFieldNames,
      cache: currentCache,
      storeName: currentStoreName,
    } = currentValuesRef.current
    if (currentKey) {
      debug(`Removing items.\nstoreName=${currentStoreName}\nbaseDatabaseKey=${currentKey}`)
      // Remove items serially to avoid race conditions
      return currentFieldNames.reduce((promise, fieldName) => {
        return promise.then(() => {
          const databaseKey = `${currentKey}:${fieldName}`
          debug(`Removing item with databaseKey=${databaseKey}`)
          return currentCache.removeItem(databaseKey)
        })
      }, Promise.resolve())
    }
    return Promise.resolve()
  }
}
