import type { ReactNode } from 'react'
import React, { createContext, useContext, useMemo } from 'react'

type Value = {
  proposedSource?: unknown
}
const ProposedSourceContext = createContext<Value>({})
export const useProposedSource = (): Value => useContext(ProposedSourceContext)

type Props = Value & {
  children: ReactNode
}
export default function ProposedSourceProvider({ proposedSource, children }: Props): JSX.Element {
  const value = useMemo(() => ({ proposedSource }), [proposedSource])
  return <ProposedSourceContext.Provider value={value}>{children}</ProposedSourceContext.Provider>
}
