/* eslint-disable sonarjs/max-switch-cases, sonarjs/cognitive-complexity -- We have a lot of different issues to account for */
import { exhaustiveCheck } from '@fs/zion-tree-types'
import { type TFunction } from 'i18next'
import {
  type CompletenessCategoryIssue,
  type CoherenceCategoryIssue,
  type VerifiabilityCategoryIssue,
  type ConsistencyCategoryIssue,
} from '../types/issues/category-issues'
import { type Issue } from '../types/scores'
import { type VerifiabilityMissingExpectedCensusIssue } from '../types/issues/verifiability-issues'

function coherenceIssueDescription({ issue, t }: { issue: CoherenceCategoryIssue; t: TFunction }): string {
  switch (issue.issueType) {
    case 'CHILD_COUNT':
      return t('person-quality-score-issues.issue-child-count.description', {
        actualChildCount: issue.actualChildCount,
        profileChildCount: issue.profileChildCount,
      })
    case 'DELAYED_BURIAL':
      return t('person-quality-score-issues.issue-delayed-burial.description', {
        actualDays: issue.actualDays,
        profileDays: issue.profileDays,
      })
    case 'IMPOSSIBLE_EVENT_ORDER':
      if (issue.firstConclusionType === 'BIRTH' && issue.secondConclusionType === 'PARENT_BIRTH') {
        return t('person-quality-score-issues.issue-impossible-event-order-birth-parent-birth.description', {
          parentGivenName: issue.parentGivenName,
        })
      }
      if (issue.firstConclusionType === 'PARENT_DEATH' && issue.secondConclusionType === 'BIRTH') {
        return t('person-quality-score-issues.issue-impossible-event-order-parent-death-birth.description', {
          parentGivenName: issue.parentGivenName,
        })
      }
      if (issue.firstConclusionType === 'DEATH' && issue.secondConclusionType === 'CHILD_BIRTH') {
        return t('person-quality-score-issues.issue-impossible-event-order-death-child-birth.description', {
          childGivenName: issue.childGivenName,
        })
      }
      if (issue.firstConclusionType === 'CHILD_BIRTH' && issue.secondConclusionType === 'BIRTH') {
        return t('person-quality-score-issues.issue-impossible-event-order-child-birth-birth.description', {
          childGivenName: issue.childGivenName,
        })
      }
      if (issue.firstConclusionType === 'DEATH' && issue.secondConclusionType === 'PARENT_BIRTH') {
        return t('person-quality-score-issues.issue-impossible-event-order-death-parent-birth.description', {
          parentGivenName: issue.parentGivenName,
        })
      }
      if (issue.firstConclusionType === 'DEATH' && issue.secondConclusionType === 'SPOUSE_BIRTH') {
        return t('person-quality-score-issues.issue-impossible-event-order-death-spouse-birth.description', {
          spouseGivenName: issue.spouseGivenName,
        })
      }
      if (issue.firstConclusionType === 'SPOUSE_DEATH' && issue.secondConclusionType === 'BIRTH') {
        return t('person-quality-score-issues.issue-impossible-event-order-spouse-death-birth.description', {
          spouseGivenName: issue.spouseGivenName,
        })
      }
      if (issue.firstConclusionType === 'CHRISTENING' && issue.secondConclusionType === 'PARENT_BIRTH') {
        return t('person-quality-score-issues.issue-impossible-event-order-christening-parent-birth.description', {
          parentGivenName: issue.parentGivenName,
        })
      }
      if (
        ['BURIAL', 'DEATH', 'CREMATION'].includes(issue.firstConclusionType) &&
        ['MARRIAGE', 'RESIDENCE'].includes(issue.secondConclusionType)
      ) {
        return t('person-quality-score-issues.issue-impossible-event-order-focus-person-single-multi.description', {
          firstConclusionType: issue.firstConclusionType,
          secondConclusionType: issue.secondConclusionType,
        })
      }
      if (['MARRIAGE', 'RESIDENCE'].includes(issue.firstConclusionType) && issue.secondConclusionType === 'BIRTH') {
        return t('person-quality-score-issues.issue-impossible-event-order-focus-person-multi-single.description', {
          firstConclusionType: issue.firstConclusionType,
          secondConclusionType: issue.secondConclusionType,
        })
      }
      return t('person-quality-score-issues.issue-impossible-event-order-focus-person.description', {
        firstConclusionType: issue.firstConclusionType,
        secondConclusionType: issue.secondConclusionType,
      })
    case 'OLD_BIRTH':
      if (issue.conclusionType === 'CHILD_BIRTH') {
        // A child of focus person is born later than expected. Focus person is parent.
        return t('person-quality-score-issues.issue-old-birth-as-parent.description', {
          childGivenName: issue.childGivenName,
          childOriginalBirthDate: issue.childOriginalBirthDate,
          actualAge: issue.actualAge,
        })
      }
      // The focus person is born later than expected. Focus person is child.
      return t('person-quality-score-issues.issue-old-birth-as-child.description', {
        parentGivenName: issue.parentGivenName,
        childOriginalBirthDate: issue.childOriginalBirthDate,
        actualAge: issue.actualAge,
      })
    case 'OLD_CHRISTENING':
      return t('person-quality-score-issues.issue-old-christening.description', {
        actualAge: issue.actualAge,
        profileAge: issue.profileAge,
      })
    case 'OLD_DEATH':
      return t('person-quality-score-issues.issue-old-death.description', {
        actualAge: issue.actualAge,
      })
    case 'OLD_MARRIAGE':
      return t('person-quality-score-issues.issue-old-marriage.description', {
        actualAge: issue.actualAge,
      })
    case 'YOUNG_BIRTH':
      if (issue.conclusionType === 'CHILD_BIRTH') {
        // A child of focus person is born earlier than expected. Focus person is parent.
        return t('person-quality-score-issues.issue-young-birth-as-parent.description', {
          childGivenName: issue.childGivenName,
          childOriginalBirthDate: issue.childOriginalBirthDate,
          actualAge: issue.actualAge,
        })
      }
      // The focus person is born earlier than expected. Focus person is child.
      return t('person-quality-score-issues.issue-young-birth-as-child.description', {
        parentGivenName: issue.parentGivenName,
        childOriginalBirthDate: issue.childOriginalBirthDate,
        actualAge: issue.actualAge,
      })
    case 'YOUNG_MARRIAGE':
      return t('person-quality-score-issues.issue-young-marriage.description', {
        actualAge: issue.actualAge,
      })
    case 'DATE_PLACE_MISMATCH':
      return t('person-quality-score-issues.issue-date-place-mismatch.description', {
        placeNormalized: issue.placeNormalized,
        placeRepId: issue.placeRepId,
        placeNormalizedFromYear: issue.placeNormalizedFromYear,
        placeNormalizedToYear: issue.placeNormalizedToYear,
        conclusionType: issue.conclusionType,
        conclusionNormalizedDate: issue.conclusionNormalizedDate,
      })
    case 'CHILDREN_BORN_TOO_CLOSE':
      return t('person-quality-score-issues.issue-children-born-too-close.description', {
        youngerSiblingGivenName: issue.youngerSiblingGivenName,
        ageGapInMonths: issue.ageGapInMonths,
        olderSiblingGivenName: issue.olderSiblingGivenName,
      })
    case 'COPARENTS_CHILDREN_BORN_TOO_CLOSE':
      return t('person-quality-score-issues.issue-coparents-children-born-too-close.description', {
        motherGivenName: issue.motherGivenName,
        youngerSiblingGivenName: issue.youngerSiblingGivenName,
        ageGapInMonths: issue.ageGapInMonths,
        olderSiblingGivenName: issue.olderSiblingGivenName,
      })
    case 'ALTERNATING_LOCATIONS':
      return t('person-quality-score-issues.issue-alternating-locations.description', {
        returnedToPlaceName: issue.returnedToPlaceName,
        movedToPlaceName: issue.movedToPlaceName,
        actualDistanceMiles: issue.actualDistanceMiles,
      })
    case 'FATHER_COUNT':
      return t('person-quality-score-issues.issue-father-count.description', {
        count: issue.count,
      })
    case 'MOTHER_COUNT':
      return t('person-quality-score-issues.issue-mother-count.description', {
        count: issue.count,
      })
    case 'PARENT_DIED_TOO_YOUNG_FOR_CHILDREN':
      return t('person-quality-score-issues.issue-parent-died-too-young-for-children.description', {
        youngPersonGivenName: issue.youngPersonGivenName,
        youngDeathAge: issue.youngDeathAge,
      })
    case 'DIED_TOO_YOUNG_FOR_CHILDREN':
      return t('person-quality-score-issues.issue-died-too-young-for-children.description', {
        youngDeathAge: issue.youngDeathAge,
      })
    case 'COPARENT_DIED_TOO_YOUNG_FOR_CHILDREN':
      return t('person-quality-score-issues.issue-coparent-died-too-young-for-children.description', {
        youngPersonGivenName: issue.youngPersonGivenName,
        youngDeathAge: issue.youngDeathAge,
      })
    case 'DIED_TOO_YOUNG_FOR_COUPLE_RELATIONSHIP':
      return t('person-quality-score-issues.issue-died-too-young-for-couple-relationship.description', {
        youngDeathAge: issue.youngDeathAge,
      })
    case 'PARTNER_DIED_TOO_YOUNG_FOR_COUPLE_RELATIONSHIP':
      return t('person-quality-score-issues.issue-partner-died-too-young-for-couple-relationship.description', {
        youngPersonGivenName: issue.youngPersonGivenName,
        youngDeathAge: issue.youngDeathAge,
      })
    case 'BORN_BEFORE_PARENTS_MARRIED':
      return t('person-quality-score-issues.issue-born-before-parents-married.description', {
        childBirthYear: issue.childBirthYear,
        yearsBeforeMarriage: issue.yearsBeforeMarriage,
        marriageYear: issue.marriageYear,
        parent1GivenName: issue.parent1GivenName,
        parent2GivenName: issue.parent2GivenName,
      })
    case 'CHILD_BORN_BEFORE_MARRIAGE':
      return t('person-quality-score-issues.issue-child-born-before-marriage.description', {
        childGivenName: issue.childGivenName,
        childBirthYear: issue.childBirthYear,
        yearsBeforeMarriage: issue.yearsBeforeMarriage,
        marriageYear: issue.marriageYear,
        parent1GivenName: issue.parent1GivenName,
        parent2GivenName: issue.parent2GivenName,
      })
    case 'COUPLE_NEVER_HAD_CHILDREN_FACT_YET_HAS_CHILDREN':
      return t('person-quality-score-issues.issue-couple-never-had-children-fact-yet-has-children.description', {
        parent1GivenName: issue.parent1GivenName,
        parent2GivenName: issue.parent2GivenName,
      })
    case 'CHILD_OF_CHILDLESS_COUPLE':
      return t('person-quality-score-issues.issue-child-of-childless-couple.description', {
        parent1GivenName: issue.parent1GivenName,
        parent2GivenName: issue.parent2GivenName,
      })
    case 'NO_CHILDREN_CONFLICT':
      return t('person-quality-score-issues.issue-no-children-conflict.description')
    case 'NO_COUPLE_RELATIONSHIPS_CONFLICT':
      return t('person-quality-score-issues.issue-no-couple-relationships-conflict.description')
    case 'DATE_PLACE_MISMATCH_UNKNOWN_TO_YEAR':
      return t('person-quality-score-issues.issue-date-place-mismatch-unknown-to-year.description', {
        placeNormalized: issue.placeNormalized,
        placeRepId: issue.placeRepId,
        placeNormalizedFromYear: issue.placeNormalizedFromYear,
        conclusionType: issue.conclusionType,
        conclusionNormalizedDate: issue.conclusionNormalizedDate,
      })
    case 'DATE_PLACE_MISMATCH_UNKNOWN_FROM_YEAR':
      return t('person-quality-score-issues.issue-date-place-mismatch-unknown-from-year.description', {
        placeNormalized: issue.placeNormalized,
        placeRepId: issue.placeRepId,
        placeNormalizedToYear: issue.placeNormalizedToYear,
        conclusionType: issue.conclusionType,
        conclusionNormalizedDate: issue.conclusionNormalizedDate,
      })
    case 'STILLBIRTH_CONFLICT':
      return t('person-quality-score-issues.issue-stillbirth-conflict.description', {
        age: issue.age,
      })
    case 'MARRIED_TO_OWN_PARENT':
    case 'MARRIED_TO_OWN_CHILD':
      return t('person-quality-score-issues.issue-improvement-married-to-own-parent-child.description', {
        spouseGivenName: issue.spouseGivenName,
      })
    default:
      throw exhaustiveCheck(issue)
  }
}

function completenessIssueDescription({ issue, t }: { issue: CompletenessCategoryIssue; t: TFunction }): string {
  switch (issue.issueType) {
    case 'DAY_NOT_SPECIFIED':
      return t(
        issue.conclusionType === 'MARRIAGE'
          ? 'person-quality-score-issues.issue-improvement-day-not-specified-multi.description'
          : 'person-quality-score-issues.issue-improvement-day-not-specified.description',
        {
          conclusionType: issue.conclusionType,
        }
      )
    case 'MONTH_NOT_SPECIFIED':
      return t(
        issue.conclusionType === 'MARRIAGE'
          ? 'person-quality-score-issues.issue-improvement-month-not-specified-multi.description'
          : 'person-quality-score-issues.issue-improvement-month-not-specified.description',
        {
          conclusionType: issue.conclusionType,
        }
      )
    case 'YEAR_NOT_SPECIFIED':
      return t(
        issue.conclusionType === 'MARRIAGE'
          ? 'person-quality-score-issues.issue-improvement-year-not-specified-multi.description'
          : 'person-quality-score-issues.issue-improvement-year-not-specified.description',
        {
          conclusionType: issue.conclusionType,
        }
      )
    case 'MISSING_EVENT_DATE':
      return t(
        issue.conclusionType === 'MARRIAGE' || issue.conclusionType === 'RESIDENCE'
          ? 'person-quality-score-issues.issue-improvement-missing-event-date-multi.description'
          : 'person-quality-score-issues.issue-improvement-missing-event-date.description',
        {
          conclusionType: issue.conclusionType,
        }
      )
    case 'MISSING_EVENT':
      return t('person-quality-score-issues.issue-improvement-missing-event.description', {
        conclusionType: issue.conclusionType,
      })
    case 'MISSING_EVENT_PLACE':
      return t(
        issue.conclusionType === 'MARRIAGE' || issue.conclusionType === 'RESIDENCE'
          ? 'person-quality-score-issues.issue-improvement-missing-event-place-multi.description'
          : 'person-quality-score-issues.issue-improvement-missing-event-place.description',
        {
          conclusionType: issue.conclusionType,
        }
      )
    case 'MISSING_PLACE_JURISDICTIONS':
      return t(
        issue.conclusionType === 'MARRIAGE' || issue.conclusionType === 'RESIDENCE'
          ? 'person-quality-score-issues.issue-improvement-missing-place-jurisdictions-multi.description'
          : 'person-quality-score-issues.issue-improvement-missing-place-jurisdictions.description',
        {
          conclusionType: issue.conclusionType,
        }
      )
    case 'NON_STANDARD_PLACE':
      return t(
        issue.conclusionType === 'MARRIAGE' || issue.conclusionType === 'RESIDENCE'
          ? 'person-quality-score-issues.issue-improvement-non-standard-place-multi.description'
          : 'person-quality-score-issues.issue-improvement-non-standard-place.description',
        {
          conclusionType: issue.conclusionType,
          originalPlace: issue.originalPlace,
        }
      )
    case 'NON_STANDARD_DATE':
      return t(
        issue.conclusionType === 'MARRIAGE' || issue.conclusionType === 'RESIDENCE'
          ? 'person-quality-score-issues.issue-improvement-non-standard-date-multi.description'
          : 'person-quality-score-issues.issue-improvement-non-standard-date.description',
        {
          conclusionType: issue.conclusionType,
          originalDate: issue.originalDate,
        }
      )
    case 'NO_GIVEN_NAME_FOUND':
      return t('person-quality-score-issues.issue-improvement-no-given-name-found.description')
    case 'NO_SURNAME_FOUND':
      return t('person-quality-score-issues.issue-improvement-no-surname-found.description')
    case 'NO_GENDER_FOUND':
      return t('person-quality-score-issues.issue-improvement-no-gender-found.description')
    default:
      throw exhaustiveCheck(issue)
  }
}

function verifiabilityIssueDescription({ issue, t }: { issue: VerifiabilityCategoryIssue; t: TFunction }): string {
  const missingExpectedCensusTranslationKeyMap = {
    1: 'person-quality-score-issues.issue-improvement-missing-expected-census-us.description',
    133: 'person-quality-score-issues.issue-improvement-missing-expected-census-canada.description',
    267: 'person-quality-score-issues.issue-improvement-missing-expected-census-england.description',
    10559523: 'person-quality-score-issues.issue-improvement-missing-expected-census-wales.description',
  } satisfies Record<VerifiabilityMissingExpectedCensusIssue['placeRepId'], string>

  switch (issue.issueType) {
    case 'MISSING_TAGGED_SOURCE':
      return t('person-quality-score-issues.issue-improvement-missing-tagged-sources.description', {
        conclusionType: issue.conclusionType,
      })
    case 'MISSING_TAGGED_SOURCE_INFORMATIONAL':
      return t('person-quality-score-issues.issue-improvement-missing-tagged-sources-informational.description', {
        conclusionType: issue.conclusionType,
      })
    case 'TOO_FEW_TAGGED_SOURCES':
      return t('person-quality-score-issues.issue-improvement-too-few-tagged-sources.description', {
        conclusionType: issue.conclusionType,
        numTags: issue.numTags,
        numTagsNeeded: issue.numTagsNeeded,
      })
    case 'TOO_FEW_TAGGED_SOURCES_INFORMATIONAL':
      return t('person-quality-score-issues.issue-improvement-too-few-tagged-sources-informational.description', {
        conclusionType: issue.conclusionType,
        numTags: issue.numTags,
        numTagsNeeded: issue.numTagsNeeded,
      })
    case 'MISSING_EXPECTED_CENSUS': {
      const translationKey = missingExpectedCensusTranslationKeyMap[issue.placeRepId]
      if (!translationKey)
        throw new Error(`placeRepId of ${issue.placeRepId.toString()} does not have an assigned translation.`)

      return t(translationKey, {
        collectionYear: issue.collectionYear,
        collectionName: issue.collectionName,
      })
    }
    case 'NO_SOURCES':
      return t('person-quality-score-issues.issue-improvement-no-sources.description')
    case 'NO_INDEXED_SOURCES':
      return t('person-quality-score-issues.issue-improvement-no-indexed-sources.description')
    case 'NO_INDEXED_CONCLUSION_SOURCES':
      return t(
        issue.conclusionType === 'MARRIAGE' || issue.conclusionType === 'RESIDENCE'
          ? 'person-quality-score-issues.issue-improvement-no-indexed-conclusion-sources-multi.description'
          : 'person-quality-score-issues.issue-improvement-no-indexed-conclusion-sources.description',
        {
          conclusionType: issue.conclusionType,
        }
      )
    case 'MULTIPLE_TAGS_IN_SAME_CENSUS':
      return t('person-quality-score-issues.issue-improvement-multiple-tags-in-same-census.description')
    default:
      throw exhaustiveCheck(issue)
  }
}

function consistencyIssueDescription({ issue, t }: { issue: ConsistencyCategoryIssue; t: TFunction }): string {
  switch (issue.issueType) {
    case 'DATE_MISMATCH':
    case 'DATE_PARTIAL_MISMATCH':
      return t('person-quality-score-issues.issue-improvement-date-mismatch.description', {
        conclusionType: issue.conclusionType,
        sourceOriginalDate: issue.sourceOriginalDate,
        conclusionOriginalDate: issue.conclusionOriginalDate,
      })
    case 'GENDER_MISMATCH':
      return t('person-quality-score-issues.issue-improvement-gender-mismatch.description')
    case 'GIVEN_NAME_MISMATCH':
      return t('person-quality-score-issues.issue-improvement-given-name-mismatch.description', {
        conclusionName: issue.conclusionName,
        sourceName: issue.sourceName,
      })
    case 'SURNAME_MISMATCH':
      return t('person-quality-score-issues.issue-improvement-surname-mismatch.description', {
        conclusionName: issue.conclusionName,
        sourceName: issue.sourceName,
      })
    case 'NO_SOURCES':
      return t('person-quality-score-issues.issue-improvement-no-sources.description')
    case 'NO_INDEXED_SOURCES':
      return t('person-quality-score-issues.issue-improvement-no-indexed-sources.description')
    case 'NO_INDEXED_CONCLUSION_SOURCES':
      return t(
        issue.conclusionType === 'MARRIAGE' || issue.conclusionType === 'RESIDENCE'
          ? 'person-quality-score-issues.issue-improvement-no-indexed-conclusion-sources-multi.description'
          : 'person-quality-score-issues.issue-improvement-no-indexed-conclusion-sources.description',
        {
          conclusionType: issue.conclusionType,
        }
      )
    case 'MISSING_SURNAME':
      return t('person-quality-score-issues.issue-improvement-missing-surname.description')
    case 'MISSING_GIVEN_NAME':
      return t('person-quality-score-issues.issue-improvement-missing-given-name.description')
    case 'PLACE_MISMATCH':
      return t('person-quality-score-issues.issue-improvement-place-mismatch.description', {
        conclusionType: issue.conclusionType,
        sourceOriginalPlace: issue.sourceOriginalPlace,
        conclusionOriginalPlace: issue.conclusionOriginalPlace,
      })
    case 'GIVEN_NAME_FIELD_MISMATCH':
      return t('person-quality-score-issues.issue-improvement-given-name-field-mismatch.description')
    case 'SURNAME_FIELD_MISMATCH':
      return t('person-quality-score-issues.issue-improvement-surname-field-mismatch.description')

    default:
      throw exhaustiveCheck(issue)
  }
}

export default function issueDescription({ issue, t }: { issue: Issue; t: TFunction }): string {
  switch (issue.scoreType) {
    case 'COHERENCE':
      return coherenceIssueDescription({ issue, t })
    case 'COMPLETENESS':
      return completenessIssueDescription({ issue, t })
    case 'CONSISTENCY':
      return consistencyIssueDescription({ issue, t })
    case 'VERIFIABILITY':
      return verifiabilityIssueDescription({ issue, t })
    default:
      throw exhaustiveCheck(issue)
  }
}
