import type { PersonId } from '@fs/zion-tree-types'
import { countsCacheService } from './caches'

export default function getFollowerCount(personId: PersonId): Promise<number> {
  const url = `/service/tree/tree-data/followers/count?personId=${personId}`
  return countsCacheService.get<{ count: number }, number>(url, `${personId}:FollowerCount`, {
    preCacheHook: (data) => data.count,
  })
}
