import axios from '@fs/zion-axios'
import { events, publish } from '@fs/zion-tree-pubsub'
import type { AxiosResponse, AxiosPromise, AxiosRequestConfig } from '@fs/zion-tree-types/zion-axios'
import type { Conclusion } from '@fs/zion-tree-types'
import { createConclusionUrl, getRelationshipType } from '../helpers/helpers'

/**
 * Delete a conclusion.
 * @param {*} conclusion - the conclusion to delete - this must contain the type and id.
 * @param {*} personIdOrRelationshipId - the id of the person or relationship that the conclusion is attached to
 * @returns {Promise} - a promise that resolves with null if successful
 */
export default async function deleteConclusion(
  conclusion: Conclusion,
  personIdOrRelationshipId: string,
  coupleId?: string
): Promise<AxiosResponse> {
  if (!conclusion.id || !personIdOrRelationshipId) {
    throw new Error('Attempted to delete a conclusion with no id or not person or relationship id')
  }
  // For association relationship we need to use the delete method and not pass "delete" to the url.
  const isAssociationType = getRelationshipType(conclusion.type) === 'association'
  return (
    axios({
      method: isAssociationType ? 'delete' : 'put',
      url: createConclusionUrl(conclusion, personIdOrRelationshipId, 'delete'),
      data: { reason: conclusion.justification || '' },
    } satisfies AxiosRequestConfig) as AxiosPromise
  )
    .then((response) => {
      // When deleting a relationship conclusion, the status is 204.
      // When deleting a non-relationship conclusion, the status is 'OK'.
      if (response.data?.status !== 'OK' && response.status !== 204) {
        throw response.data
      }
      const relationshipType = getRelationshipType(conclusion.type)
      const key = relationshipType ? 'relationshipId' : 'personId'
      const data = {
        action: 'delete',
        conclusion: { type: conclusion.type },
        [key]: personIdOrRelationshipId,
        relationshipType,
        coupleId,
      }
      const evt = events.conclusion
      publish({ evt, data })
      return response.data.data ?? response.data
    })
    .catch((error) => {
      if (typeof error.response?.status === 'number') {
        // Handle unwrapped response by mimicking wrapped response
        throw { status: 'NOT OK', data: {} } // eslint-disable-line no-throw-literal -- mimick wrapped response
      }
      throw error
    })
}
