import React from 'react'
import { Row, IconButton } from '@fs/zion-ui'
import { useTranslation } from 'react-i18next'
import { ControlExpand, ControlFullscreenExit } from '@fs/zion-icon'

type Props = {
  expandContent: boolean
  setExpandContent: React.Dispatch<React.SetStateAction<boolean>>
}
export default function ExpandContentSwitch({ expandContent, setExpandContent }: Props): JSX.Element {
  const [t] = useTranslation()
  const title = expandContent ? t('conclusion.collapse-content.action') : t('conclusion.expand-content.action')
  const dataTestId = expandContent ? 'collapse-content-button' : 'expand-content-button'

  return (
    <Row gutters="none" alignY="top" wrap={false} alignX="end">
      <div growX />
      <IconButton
        noShrinkX
        data-testid={dataTestId}
        tabIndex={0}
        title={title}
        Icon={expandContent ? ControlFullscreenExit : ControlExpand}
        onClick={() => setExpandContent(!expandContent)}
        linkName={expandContent ? 'conclusion:collapse-content' : 'conclusion:expand-content'}
      />
    </Row>
  )
}
