import React, { useCallback, useRef, useEffect } from 'react'
import * as Yup from 'yup'
import { yupResolver } from '@hookform/resolvers/yup'
import ZionForm, { useZionForm, FormTextArea, type UseFormResetField } from '@fs/zion-form'
import SuggestedReasons, { zionFormOnAddReason } from '@fs/zion-suggested-reasons'
import { useTranslation } from 'react-i18next'
import { useFeatureFlag } from '@fs/zion-flags'
import { css } from '@linaria/core'

type FormValues = {
  reason: string
}

const reasonInputWrapper = css`
  max-width: 80ch;
  margin: 0 auto;
`

type ReasonFormProps = {
  label: string
  loading?: boolean
  onSubmit: (values: FormValues, resetField: UseFormResetField<FormValues>) => void
  'data-testid'?: string
  defaultValues?: FormValues
  setDisabled?: (isValid: boolean) => void
  suggestedReasonProps?: Record<string, unknown>
}

export default function ReasonForm({
  label,
  loading,
  onSubmit,
  'data-testid': dataTestid,
  defaultValues = { reason: '' },
  setDisabled,
  suggestedReasonProps,
}: ReasonFormProps): JSX.Element {
  const { t } = useTranslation()
  const reasonRequired = dataTestid === 'conclusion:dead-to-living:reason'
  const errorMessage = t('conclusion.validation.error.reason-required')

  const validationSchema = Yup.object().shape({
    reason: Yup.string().trim().min(4, errorMessage).required(errorMessage),
  })

  const methods = useZionForm({
    mode: 'all',
    defaultValues,
    resolver: reasonRequired ? yupResolver(validationSchema) : undefined,
  })

  const {
    setValue,
    getValues,
    formState: { isValid },
    resetField,
  } = methods

  useEffect(() => {
    if (setDisabled) {
      setDisabled(isValid)
    }
  }, [isValid, setDisabled])

  const textAreaRef = useRef<HTMLTextAreaElement>(null)

  const onAddReason = useCallback(
    (reason) => {
      zionFormOnAddReason({ name: 'reason', setValue, getValues })(reason)
      textAreaRef?.current?.focus?.()
    },
    [setValue, getValues]
  )
  const suggestedReasonsFlag = useFeatureFlag('treeWeb_suggestedReasons')

  return (
    <ZionForm
      id="reason-form"
      data-testid="reason-form"
      methods={methods}
      onSubmit={(values) => onSubmit(values, resetField)}
    >
      <div className={reasonInputWrapper}>
        <FormTextArea
          autoFocus
          disabled={loading}
          label={label}
          name="reason"
          data-testid={dataTestid || 'reason-textarea'}
          ref={textAreaRef}
          maxLength={2000}
        />

        {suggestedReasonProps?.type && suggestedReasonsFlag.isOn && (
          <SuggestedReasons {...suggestedReasonProps} onAddReason={onAddReason} />
        )}
      </div>
    </ZionForm>
  )
}
