import React, {
  type ComponentType,
  forwardRef,
  type ForwardRefExoticComponent,
  type HTMLAttributes,
  type PropsWithoutRef,
  type ReactNode,
  type RefAttributes,
} from 'react'
import { CheckboxGroup, RadioGroup, ToggleGroup, InputGroup } from '@fs/zion-ui'
import { useWatch, useFormState, type FieldValues, type FieldPath } from 'react-hook-form'
import { useZionFormContext, getByPath } from './Form'

type SharedProps<TFieldValues extends FieldValues = FieldValues> = {
  allowLabelWrapping?: boolean

  /** Label text for the group of inputs.  JSX is allowed, but please don't use for anything except links. */
  label?: string | ReactNode

  /** Increases label size when set to true */
  largerLabel?: boolean

  /** Determines the direction the inputs are laid out. */
  orientation?: 'horizontal' | 'vertical'

  /** Disables the entire radio group if true. */
  disabled?: boolean

  /** Use this property to remove the built-in spacing when needed. */
  dense?: boolean

  /** Function that determines whether to display a warning message. It is called with an object of values for `fieldsToValidate` and returns a warning message to display. If you depend on the values of any fields to run your warningValidate function, you need to include them in the `namesOfFieldsToValidate` so they will trigger the function on change. */
  warningValidate?: (watchedValues: Record<string, unknown>) => string | null | undefined

  /* Help text to display below the group */
  helpMessage?: string

  /* Message to display when the fields are valid */
  validMessage?: string

  /** The names of the fields that the group should show validation for. This should also include the names of any fields that should trigger the warningValidate function to run. */
  namesOfFieldsToValidate?: FieldPath<TFieldValues>[]

  /** Force warningValidate to show up before a field is touched or the form is submitted */
  ignoreTouchedForWarnings?: boolean

  children?: ReactNode
} & Omit<HTMLAttributes<HTMLDivElement>, 'className' | 'css'>

function hookUpGroupFields<TFieldValues extends FieldValues>(
  Component: ComponentType<SharedProps<TFieldValues>>
): ForwardRefExoticComponent<PropsWithoutRef<SharedProps<TFieldValues>> & RefAttributes<HTMLElement>> {
  return forwardRef<HTMLElement, SharedProps<TFieldValues>>(
    // eslint-disable-next-line @typescript-eslint/no-unused-vars -- ref cannot be passed on because none of the Component components are forwardRefs.
    ({ warningValidate, validMessage, namesOfFieldsToValidate, ignoreTouchedForWarnings, ...props }, _ref) => {
      const {
        config: { mode },
      } = useZionFormContext<TFieldValues>()
      const { errors, isSubmitted, touchedFields, dirtyFields } = useFormState()

      // Default to empty array if not provided, which will result in no fields being watched
      const fieldsToValidate = namesOfFieldsToValidate ?? ([] as FieldPath<TFieldValues>[])

      const isTouched = fieldsToValidate.some((name) => getByPath(name, touchedFields))
      const isDirty = fieldsToValidate.some((name) => getByPath(name, dirtyFields))

      // Always call useWatch (hooks must be unconditional), but with empty array if no fields specified
      const watchedValuesArray = useWatch({ name: fieldsToValidate.length > 0 ? fieldsToValidate : [] })

      // Convert array of values to object keyed by field name
      const watchedValues = (Array.isArray(watchedValuesArray) ? watchedValuesArray : []).reduce(
        (combinedObj, value, index) => {
          if (fieldsToValidate[index]) {
            combinedObj[fieldsToValidate[index]] = value
          }
          return combinedObj
        },
        {} as Record<string, unknown>
      )
      let didValidationRunForFields = false
      if (mode === 'onSubmit') {
        didValidationRunForFields = isSubmitted
      } else if (mode && ['onBlur', 'onTouched', 'all'].includes(mode)) {
        didValidationRunForFields = isSubmitted || isTouched
      } else if (mode === 'onChange') {
        // onChange doesn't run validation on blur, so we have to ensure that the field has been changed at least once. This doesn't quite do that - because something could get dirty then undirty, but we have no way of saying "has been changed since the last reset"
        didValidationRunForFields = isSubmitted || (isTouched && isDirty)
      }

      let errorMessage
      fieldsToValidate.some((name) => {
        const error = getByPath(name, errors)
        if (error && typeof error === 'object' && 'message' in error && error?.message) {
          errorMessage = error.message
          return true
        }
        if (
          error &&
          typeof error === 'object' &&
          'root' in error &&
          error?.root &&
          typeof error.root === 'object' &&
          'message' in error.root &&
          error.root.message
        ) {
          errorMessage = error.root.message
          return true
        }
        return false
      })
      // We do not want validation messages to show until either the field has been touched (which happens on the first blur from the field) or the form has been submitted. We make an exception where we can show warnings without being touched if the prop is explicitly set.
      const messages = {
        errorMessage: didValidationRunForFields ? errorMessage : undefined,
        validMessage: didValidationRunForFields ? validMessage : undefined,
        warningMessage:
          didValidationRunForFields || ignoreTouchedForWarnings
            ? warningValidate?.(watchedValues) // We only pass in the watchedValues to warningValidate because we can only guarantee the function will run when these specific values change. If you need something during your warningValidate function, it should be in the `namesOfFieldsToValidate` list.
            : undefined,
      }

      return <Component {...props} {...messages} />
    }
  )
}

export const FormCheckboxGroup = hookUpGroupFields(CheckboxGroup)
export const FormRadioGroup = hookUpGroupFields(RadioGroup)
export const FormToggleGroup = hookUpGroupFields(ToggleGroup)
export const FormInputGroup = hookUpGroupFields(InputGroup)

// eslint-disable-next-line @typescript-eslint/no-unused-vars -- For storybook docs
export const FormGroupProps = (_props: SharedProps): null => null
