import React, { useState, type UIEvent } from 'react'
import { ListItem, colors, useContainerWidth, useOverlay, useStatusOverlay } from '@fs/zion-ui'
import { NoticeSuggestion, NoticeLoading, MenuClose } from '@fs/zion-icon'
import { useTranslation } from 'react-i18next'
import type { ShowStatusOverlayProps } from '@fs/zion-tree-types/zion-ui'
import { type PID } from '@fs/zion-tree-types'
import type { Issue } from '../types/scores'
import issueDescription from '../helpers/issueDescription'
import dismissIssue from '../services/dismissIssue'
import { DismissDialog } from './DismissDialog'

type Props = {
  issue: Issue
  onClick?: (e: UIEvent, issue: Issue) => void
  personId?: PID
  onDismissed?: (issueId: string) => void
}

export default function IssueImprovement({ issue, onClick, personId, onDismissed }: Props): JSX.Element {
  const [t] = useTranslation()
  const [isDismissing, setIsDismissing] = useState(false)
  const showStartElement = useContainerWidth()({ default: false, nano: true })
  const dismissOverlay = useOverlay()
  const showStatusOverlay = useStatusOverlay() as (props: ShowStatusOverlayProps) => JSX.Element
  const onClickWrapper = onClick ? (e: UIEvent): void => onClick(e, issue) : undefined

  const handleDismissConfirm = async ({ reasonStatement }: { reasonStatement: string }): Promise<void> => {
    // Guard against missing personId or onDismissed, which should never happen since the dismiss button shouldn't render.
    if (!personId || !onDismissed) return
    setIsDismissing(true)
    try {
      await dismissIssue({ personId, issueId: issue.id, reason: reasonStatement })
      dismissOverlay.close()
      onDismissed(issue.id)
    } catch {
      showStatusOverlay({
        message: t('person-quality-score-issues.dismiss.error'),
        type: 'error',
        dismissable: true,
      })
    } finally {
      setIsDismissing(false)
    }
  }

  return (
    <>
      <ListItem
        primaryText={issueDescription({ issue, t })}
        secondaryText={'sourceTitle' in issue ? issue.sourceTitle : undefined}
        startElement={showStartElement ? <ListItem.Icon Icon={NoticeSuggestion} color={colors.purple60} /> : undefined}
        onClick={onClickWrapper}
        endElement={
          personId && onDismissed && issue.dismissible ? (
            <ListItem.IconButton
              Icon={isDismissing ? NoticeLoading : MenuClose}
              onClick={dismissOverlay.handleClick}
              disabled={isDismissing}
              aria-label={t('common-ui:dismiss.action')}
              data-testid={`dismiss-issue-${issue.id}`}
            />
          ) : undefined
        }
      />
      {(dismissOverlay.isOpen || dismissOverlay.transitioning) && (
        <DismissDialog
          dismissOverlay={dismissOverlay}
          handleDismiss={handleDismissConfirm}
          isDismissing={isDismissing}
          issue={issue}
        />
      )}
    </>
  )
}
