import type { Conclusion } from '@fs/zion-tree-types'
import type { AxiosResponse } from '@fs/zion-tree-types/zion-axios'
import axios from '@fs/zion-axios'
import type { QualityScoreValidationPayload, QualityScoreValidationResponse } from '../types/qualityScore'

type Props = {
  personId: string

  /** The existing conclusion being edited */
  conclusionToEdit?: Conclusion

  /** The new conclusion being added */
  conclusionToAdd?: Conclusion

  /** The conclusion ID being deleted */
  conclusionToDelete?: string
}

/**
 * Validates if saving/deleting a conclusion will decrease a person's quality score
 */
export default async function validateConclusionQuality({
  personId,
  conclusionToEdit,
  conclusionToAdd,
  conclusionToDelete,
}: Props): Promise<{ shouldWarn: boolean; response?: QualityScoreValidationResponse }> {
  try {
    const payload: QualityScoreValidationPayload = {}

    if (conclusionToEdit) {
      payload.conclusionToEdit = conclusionToEdit
    }

    if (conclusionToAdd) {
      payload.conclusionToAdd = conclusionToAdd
    }

    if (conclusionToDelete) {
      payload.conclusionToDelete = conclusionToDelete
    }

    const response: AxiosResponse<QualityScoreValidationResponse> = await axios({
      method: 'post',
      url: `/service/tree/tree-data/quality/person/${personId}/conclusion`,
      data: payload,
    })

    // Handle 204 response (no warning needed)
    if (response.status === 204) {
      return { shouldWarn: false }
    }

    // Handle 200 response (warning needed)
    if (response.status === 200 && response.data) {
      return {
        shouldWarn: response.data.personScoresDelta?.shouldWarn ?? false,
        response: response.data,
      }
    }

    // Default to no warning if we get an unexpected response
    return { shouldWarn: false }
  } catch (error) {
    // If the service is unavailable or returns an error, don't block the save process
    // Silently fail and return no warning to avoid blocking saves
    return { shouldWarn: false }
  }
}
