import type { Ref } from 'react'
import React from 'react'
import { css } from '@linaria/core'
import { boolAttr } from '@fs/zion-frontend-friends'
import type { LifeSketchConclusion } from '@fs/zion-tree-types'

// Pretty much the same css as in Ellipsis, but with pre-wrap
const lifesketchCss = css`
  display: block;
  max-width: 100%;
  overflow: hidden;
  white-space: pre-wrap;
  &[data-preview] {
    display: -webkit-box;
    -webkit-box-orient: vertical;
    -webkit-line-clamp: 4;
  }
`
type RenderTheSketchProps = {
  /** If true, only the first four lines will be displayed. */
  preview?: boolean

  /** The lifesketch conclusion object. */
  lifesketch?: LifeSketchConclusion

  /** A ref to point focus on. Used internally by ConclusionDialog. */
  focusRef?: Ref<HTMLDivElement>
}

/**
 * Render a lifesketch, accounting for whether we're in preview mode or not.
 * Zion Ellipsis will not work well here, since we need white-space: pre-wrap.
 */
export default function RenderTheSketch({ preview, lifesketch, focusRef }: RenderTheSketchProps): JSX.Element {
  return (
    <div ref={focusRef} data-testid="lifesketch-contents" data-preview={boolAttr(preview)} className={lifesketchCss}>
      {lifesketch?.details?.text ?? ''}
    </div>
  )
}
