import type { ConclusionType } from '@fs/zion-tree-types'
import { addFormDefaultValues, getFieldsForConclusion } from './helpers'
import type { FormValues } from '../types/form'

export const constructDefaultValues = ({
  conclusionType,
  defaultNameTemplate,
  conclusionToFormValues,
}: {
  conclusionType?: ConclusionType
  defaultNameTemplate: string | null
  conclusionToFormValues: Record<string, unknown>
}): FormValues => {
  // conclusionToFormValues is passed in rather than calculated because the component needs to also use the
  // form values to get the default name template, so we won't have to do that calculation more than once
  const fields = getFieldsForConclusion(conclusionType)
  let defaultValues = fields.reduce<FormValues>((accum, field) => {
    if (field === 'template') {
      accum.template = defaultNameTemplate ?? 'und'
    } else if (field === 'event') {
      accum.event = conclusionType === 'ENSLAVEMENT' || conclusionType === 'EMANCIPATION' ? conclusionType : undefined
    } else {
      accum[field] = addFormDefaultValues[field]
    }
    return accum
  }, {})
  const definedConclusionValues = Object.fromEntries(
    Object.entries(conclusionToFormValues).filter(([, value]) => value != null)
  )
  defaultValues = { ...defaultValues, ...definedConclusionValues }
  return defaultValues
}
