import React from 'react'
import { useTranslation } from 'react-i18next'
import { dialogCategoryHeadings } from '../helpers/helpers'

export type IssueType = keyof typeof dialogCategoryHeadings

type Props = {
  issueType: IssueType
  issueCount: number
}

export default function IssueLabel({ issueType, issueCount }: Props): JSX.Element {
  const [t] = useTranslation()
  const headingKey = dialogCategoryHeadings[issueType].headingKey
  return <>{t(headingKey, { issueCount })}</>
}
