import React, { useRef, useEffect, useState } from 'react'
import { DialogOverlay, DialogOverlayActions, Button, Row, List, H3, Separator } from '@fs/zion-ui'
import { useTranslation } from 'react-i18next'
import { IssueImprovement } from '@fs/zion-person-quality-score-issues'
import { trackEvent } from '@fs/zion-analytics'
import type { UseOverlayReturnOptions } from '@fs/zion-ui'
import ZionForm, { type FieldErrors, FormTextArea, useZionForm } from '@fs/zion-form'
import { useSyncDialogFieldToStorage } from '@fs/zion-storage-sync'
import type { QualityScoreIssue, PersonScoresDelta } from '../../types/qualityScore'
import { calculateScoreChange } from './helperFunctions'

const MAX_VISIBLE_ISSUES = 3

// Component to display issues grouped by score type with "view more" functionality
function IssuesList({ issues }: { issues: QualityScoreIssue[] }): JSX.Element {
  const [t] = useTranslation()
  const [expanded, setExpanded] = useState<boolean>(false)

  // Sort issues within each group by penalty (descending)
  const sortedIssues = issues.toSorted((a, b) => b.penalty - a.penalty)

  const toggleExpanded = (): void => {
    setExpanded((prev) => !prev)
  }

  const hasMoreIssues = sortedIssues.length > MAX_VISIBLE_ISSUES
  const visibleIssues = expanded ? sortedIssues : sortedIssues.slice(0, MAX_VISIBLE_ISSUES)

  return (
    <>
      <H3 size="H6">{t('conclusion.conflicts-count.label', { count: sortedIssues.length })}</H3>
      <List>
        {visibleIssues.map((issue) => (
          <IssueImprovement key={issue.id} issue={issue} />
        ))}
      </List>
      {hasMoreIssues && (
        <Button emphasis="low" onClick={toggleExpanded}>
          {expanded
            ? t('conclusion.quality-score-warning.view-less')
            : t('conclusion.quality-score-warning.view-more', {
                count: sortedIssues.length - MAX_VISIBLE_ISSUES,
              })}
        </Button>
      )}
    </>
  )
}

type FormValues = {
  reason: string
}

type QualityScoreWarningDialogProps = {
  overlay: UseOverlayReturnOptions
  defaultValues: FormValues
  onSave: (values: FormValues) => void
  onCancel: () => void
  personScoresDelta?: PersonScoresDelta
  /** Add conclusion type for analytics */
  conclusionType?: string
  actionType?: 'Add' | 'Edit' | 'Delete'
  personName: string
}

export default function QualityScoreWarningDialog({
  overlay,
  onSave,
  onCancel,
  defaultValues,
  personScoresDelta,
  personName,
  conclusionType,
  actionType,
}: QualityScoreWarningDialogProps): JSX.Element {
  const [t] = useTranslation()
  const saveRef = useRef<HTMLButtonElement>(null)

  const methods = useZionForm<FormValues>({
    mode: 'all',
    defaultValues,
    resolver: async (values) => {
      const errors: FieldErrors<FormValues> = {}

      if (!values.reason.trim()) {
        errors.reason = { type: 'required', message: t('conclusion.required.error') }
      }

      // Return empty values object when there are errors, per react-hook-form resolver contract
      if (Object.keys(errors).length > 0) {
        return { values: {}, errors }
      }

      return {
        values,
        errors: {},
      }
    },
  })

  const { resetField } = methods

  // Reset the field when dialog opens with the latest default value from parent
  useEffect(() => {
    if (overlay.isOpen) {
      resetField('reason', { defaultValue: defaultValues.reason })
    }
  }, [overlay.isOpen, defaultValues.reason, resetField])

  useSyncDialogFieldToStorage({
    fieldName: 'reason',
    databaseKey: `${actionType}:${conclusionType}:reason`,
    methods,
    storeName: 'conclusionQualityScoreWarningDialog',
    isOpen: overlay.isOpen,
    defaultValue: defaultValues.reason,
  })

  // Track if Person Quality Score will be higher or lower with this edit.
  const scoreChange = calculateScoreChange(
    personScoresDelta?.currentScores.overallRawScore,
    personScoresDelta?.newScores.overallRawScore
  )

  // Track conclusion dialog shown when THIS overlay is open
  useEffect(() => {
    if (!overlay.isOpen) return
    trackEvent({
      event_name: 'conclusion_quality_score_warning_dialog_shown',
      issues_count: personScoresDelta?.issuesAdded.length,
      quality_score_saved: scoreChange,
      conclusion_type: conclusionType,
      action_type: actionType,
    })
  }, [overlay.isOpen, personScoresDelta?.issuesAdded.length, scoreChange, conclusionType, actionType])

  const handleSave = (values: FormValues): void => {
    trackEvent({
      event_name: 'conclusion_quality_score_warning_dialog_save_clicked',
      issues_count: personScoresDelta?.issuesAdded.length,
      quality_score_saved: scoreChange,
      conclusion_type: conclusionType,
      action_type: actionType,
    })

    onSave(values)
    overlay.close()
  }

  const handleCancel = (): void => {
    onCancel()
    overlay.close()
  }

  return (
    <DialogOverlay
      {...overlay}
      as={ZionForm<FormValues>}
      size="lg"
      methods={methods}
      onSubmit={handleSave}
      focusRef={saveRef}
      title={t('conclusion.will-lower-quality-score.heading', {
        name: personName,
      })}
      subtitle={t('conclusion.will-lower-quality-score.subheading')}
      footer={
        <DialogOverlayActions>
          <Row>
            <Button data-testid="qualityScoreWarningCancelButton" onClick={handleCancel}>
              {t('common-ui:cancel.action')}
            </Button>

            <Button
              ref={saveRef}
              data-testid="qualityScoreWarningSaveButton"
              type="submit"
              emphasis="high"
              disabled={!methods.formState.isValid}
            >
              {t('common-ui:save.action')}
            </Button>
          </Row>
        </DialogOverlayActions>
      }
    >
      {personScoresDelta?.issuesAdded && personScoresDelta.issuesAdded.length > 0 && (
        <IssuesList issues={personScoresDelta.issuesAdded} />
      )}
      <Separator size="nano" />
      <FormTextArea label={t('conclusion.will-lower-quality-score-reason.label')} name="reason" />
    </DialogOverlay>
  )
}
