import React, { useState } from 'react'
import {
  DialogOverlay,
  useStatusOverlay,
  DialogOverlayFooter,
  DialogOverlayActions,
  Button,
  Paragraph,
  Row,
  Skeleton,
} from '@fs/zion-ui'
import { NoticeLoading } from '@fs/zion-icon'
import { useTranslation } from 'react-i18next'
import type { PersonId, VitalEventConclusion } from '@fs/zion-tree-types'
import type { UseOverlayReturnOptions } from '@fs/zion-ui'
import ReasonForm from '../ReasonForm'
import { useHasSupportCase, useCreateSupportCase } from '../../data-service/deadToLivingService'

type DeadToLivingContentProps = {
  hasCase: boolean
  close: () => void
  onConfirm?: () => void
  personId: PersonId
  conclusion: VitalEventConclusion
  personName?: string
}

const DeadToLivingContent = ({
  hasCase,
  close,
  onConfirm,
  personId,
  conclusion,
  personName,
}: DeadToLivingContentProps): JSX.Element => {
  const { t } = useTranslation()
  const showStatusOverlay = useStatusOverlay()
  const [{ loading }, createSupportCase] = useCreateSupportCase()
  const [formIsValid, setDisabled] = useState(false)
  const onSubmit = ({ reason: justification }): void => {
    createSupportCase({
      personId,
      personName,
      currentDeathConclusion: conclusion,
      justification,
    })
      .then(({ data }) => {
        if (data?.status !== 'OK') throw new Error(data?.status)
        showStatusOverlay({
          type: 'success',
          message: t('conclusion.dead-to-living.success'),
        })
        onConfirm?.()
        close()
      })
      .catch(() => {
        showStatusOverlay({
          type: 'error',
          message: t('conclusion.ERROR_RAISE_FROM_DEAD_FAILED'),
        })
      })
  }
  return (
    <>
      {hasCase ? (
        <Paragraph size="sm">{t('conclusion.dead-to-living.request-submitted')}</Paragraph>
      ) : (
        <>
          <Paragraph size="sm">{t('conclusion.dead-to-living.body')}</Paragraph>
          <ReasonForm
            onSubmit={onSubmit}
            loading={loading}
            label={t('conclusion.dead-to-living.label')}
            setDisabled={setDisabled}
            data-testid="conclusion:dead-to-living:reason"
          />
        </>
      )}

      <DialogOverlayFooter>
        <DialogOverlayActions>
          {hasCase ? (
            <Button
              data-testid="conclusion:dead-to-living:ok"
              onClick={() => {
                onConfirm?.()
                close()
              }}
            >
              {t('common-ui:ok.action')}
            </Button>
          ) : (
            <Row>
              <Button data-testid="conclusion:dead-to-living:cancel" onClick={close}>
                {t('common-ui:cancel.action')}
              </Button>

              <Button
                data-testid="conclusion:dead-to-living:submit"
                disabled={!formIsValid || loading}
                emphasis="high"
                form="reason-form"
                Icon={loading ? NoticeLoading : undefined}
                type="submit"
              >
                {t('common-ui:submit.action')}
              </Button>
            </Row>
          )}
        </DialogOverlayActions>
      </DialogOverlayFooter>
    </>
  )
}

const Loading = (): JSX.Element => {
  return (
    <>
      <Skeleton.Paragraph lineCount={5} size="md" />

      <DialogOverlayFooter>
        <DialogOverlayActions>
          <Skeleton.Button />
          <Skeleton.Button />
        </DialogOverlayActions>
      </DialogOverlayFooter>
    </>
  )
}

type DeadToLivingDialogProps = Record<string, unknown> & {
  personId: PersonId
  overlay: UseOverlayReturnOptions
  conclusion: VitalEventConclusion
}

export default function DeadToLivingDialog({ personId, overlay, ...rest }: DeadToLivingDialogProps): JSX.Element {
  const { t } = useTranslation()
  const { loading, hasCase } = useHasSupportCase(personId, overlay.close)

  return (
    <DialogOverlay {...overlay} title={t('conclusion.dead-to-living.heading')}>
      {loading ? (
        <Loading />
      ) : (
        <DeadToLivingContent hasCase={hasCase} close={overlay.close} personId={personId} {...rest} />
      )}
    </DialogOverlay>
  )
}
