import React, { type ComponentType } from 'react'
import type { Conclusion, ConclusionType, PersonId } from '@fs/zion-tree-types'
import { type SourceListProps } from '@fs/zion-tree-types/zion-source-list'
import { useProposedSource } from '../ProposedSourceProvider'
import { getConclusionCategory } from '../../helpers/helpers'

const mapToConclusionType = {
  BIRTH: 'Birth',
  DEATH: 'Death',
  CHRISTENING: 'Christening',
  BURIAL: 'Burial',
  NAME: 'Name',
  GENDER: 'Gender',
  STILLBORN: 'Stillbirth',
  STILLBIRTH: 'Stillbirth',
  BAR_MITZVAH: 'BarMitzvah',
  BAT_MITZVAH: 'BatMitzvah',
  BAS_MITZVAH: 'BatMitzvah',
  CREMATION: 'Cremation',
  NATIONALITY: 'Nationality',
  PHYSICAL_DESCRIPTION: 'PhysicalDescription',
  LIFE_SKETCH: 'LifeSketch',
  NO_COUPLE_RELATIONSHIPS: 'NoCoupleRelationships',
  COUPLE_NEVER_HAD_CHILDREN: 'NoChildren',
  NO_CHILDREN: 'NoChildren',
  NATIONAL_ORIGIN: 'Nationality',
} as const

function getSourceListEntityType(conclusionCategory): 'couple' | 'person' | 'parentchild' | 'association' {
  if (conclusionCategory.includes('couple')) return 'couple'
  if (conclusionCategory.includes('parentChild')) return 'parentchild'
  if (conclusionCategory.includes('association')) return 'association'
  return 'person'
}

type ConclusionSourceListProps = {
  conclusion: Conclusion | undefined
  personId?: PersonId
  relationshipId?: string
  readOnly?: boolean
  // type is used when using ConclusionWithAdd
  type?: ConclusionType
  SourceListComponent: ComponentType<SourceListProps>
}

export default function ConclusionSourceList({
  type,
  conclusion,
  personId,
  relationshipId,
  readOnly,
  SourceListComponent,
}: ConclusionSourceListProps): JSX.Element | null {
  const conclusionType = conclusion?.type || type
  const conclusionCategory = getConclusionCategory(conclusionType)
  const entityType = getSourceListEntityType(conclusionCategory)
  const { proposedSource } = useProposedSource() ?? {}

  const entityId = entityType === 'person' ? personId : relationshipId

  if (!entityId) return null

  return (
    <div data-testid="conclusionDetailOverlay:sources-wrapper">
      <SourceListComponent
        conclusionId={conclusion?.id}
        conclusionType={conclusionType ? mapToConclusionType[conclusionType] : undefined}
        entityId={entityId}
        entityType={entityType}
        hideOptions
        hideSourceAddButton
        hideTableHeaders
        hideActionButtons={readOnly}
        sourceTagOverlayProps={{ closeOnClickAway: false }}
        proposedSource={proposedSource}
      />
    </div>
  )
}
